{
  "name": "GamiRoutine - Sua Rotina Gamificada",
  "description": "Transforme suas tarefas diárias em uma jornada épica. Ganhe XP, acumule moedas e resgate recompensas personalizadas enquanto mantém sua produtividade.",
  "requestFramePermissions": [
    "notifications"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Task {
  id: string;
  title: string;
  xp: number;
  coins: number;
  completed: boolean;
  dueDate?: string; // ISO string
  reminderSet: boolean;
}

export interface Reward {
  id: string;
  title: string;
  cost: number;
  purchased: boolean;
  description: string;
}

export interface UserStats {
  totalXp: number;
  totalCoins: number;
  level: number;
}

export interface AppData {
  tasks: Task[];
  rewards: Reward[];
  stats: UserStats;
}

export type View = 'dashboard' | 'tasks' | 'shop' | 'settings';

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, UserStats, AppData } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  stats: {
    totalXp: 0,
    totalCoins: 0,
    level: 1
  }
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  // Save to local storage whenever data changes
  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const updateData = (newData: Partial<AppData>) => {
    setData(prev => ({ ...prev, ...newData }));
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true } : t
    );

    const newXp = data.stats.totalXp + task.xp;
    const newCoins = data.stats.totalCoins + task.coins;
    const newLevel = Math.floor(newXp / 1000) + 1;

    updateData({
      tasks: newTasks,
      stats: {
        totalXp: newXp,
        totalCoins: newCoins,
        level: newLevel
      }
    });
  };

  const handlePurchaseReward = (rewardId: string) => {
    const reward = data.rewards.find(r => r.id === rewardId);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const newCoins = data.stats.totalCoins - reward.cost;
    const newRewards = data.rewards.filter(r => r.id !== rewardId); // Consume after purchase or mark as purchased

    updateData({
      rewards: newRewards,
      stats: { ...data.stats, totalCoins: newCoins }
    });
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard 
                  stats={data.stats} 
                  tasks={data.tasks} 
                  rewards={data.rewards} 
                  onCompleteTask={handleCompleteTask}
                  onPurchaseReward={handlePurchaseReward}
                />;
      case 'tasks':
        return <TaskManager 
                  tasks={data.tasks} 
                  onUpdateTasks={(tasks) => updateData({ tasks })}
                />;
      case 'shop':
        return <RewardShop 
                  rewards={data.rewards} 
                  coins={data.stats.totalCoins}
                  onUpdateRewards={(rewards) => updateData({ rewards })}
                  onPurchase={handlePurchaseReward}
                />;
      case 'settings':
        return <Settings 
                  data={data} 
                  onImport={(importedData) => setData(importedData)}
                />;
      default:
        return <Dashboard stats={data.stats} tasks={data.tasks} rewards={data.rewards} onCompleteTask={handleCompleteTask} onPurchaseReward={handlePurchaseReward} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-xs text-slate-400 font-medium">Nível {data.stats.level}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center bg-blue-50 px-3 py-1 rounded-full border border-blue-200">
                <span className="text-sm font-bold text-blue-600 mr-1">✨</span>
                <span className="text-sm font-bold text-blue-600">{data.stats.totalXp} XP</span>
            </div>
            <div className="flex items-center bg-green-50 px-3 py-1 rounded-full border border-green-200">
                <span className="text-sm font-bold text-green-600 mr-1">🪙</span>
                <span className="text-sm font-bold text-green-600">{data.stats.totalCoins}</span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {renderView()}
      </main>

      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React from 'react';
import { View } from '../types';

interface NavbarProps {
  activeView: View;
  setView: (view: View) => void;
}

const Navbar: React.FC<NavbarProps> = ({ activeView, setView }) => {
  const items = [
    { id: 'dashboard' as View, label: 'Início', icon: '🏠' },
    { id: 'tasks' as View, label: 'Tarefas', icon: '📝' },
    { id: 'shop' as View, label: 'Loja', icon: '🎁' },
    { id: 'settings' as View, label: 'Ajustes', icon: '⚙️' },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-blue-100 flex justify-around items-center px-4 py-3 safe-bottom shadow-lg z-50">
      {items.map((item) => (
        <button
          key={item.id}
          onClick={() => setView(item.id)}
          className={`flex flex-col items-center gap-1 transition-all duration-200 ${
            activeView === item.id ? 'text-blue-600 scale-110' : 'text-slate-400'
          }`}
        >
          <span className="text-2xl">{item.icon}</span>
          <span className="text-[10px] font-bold uppercase tracking-wider">{item.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { Task, Reward, UserStats } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, onCompleteTask, onPurchaseReward }) => {
  const pendingTasks = tasks.filter(t => !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const xpProgress = (stats.totalXp % 1000) / 10;

  return (
    <div className="p-6 space-y-6">
      {/* Progress Card */}
      <section className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-3xl p-6 text-white shadow-xl shadow-blue-200">
        <h3 className="text-blue-100 text-sm font-medium mb-1">Seu Progresso de Nível</h3>
        <div className="flex justify-between items-end mb-3">
          <span className="text-3xl font-bold">Nível {stats.level}</span>
          <span className="text-blue-100 text-sm font-medium">{stats.totalXp % 1000} / 1000 XP</span>
        </div>
        <div className="w-full bg-blue-700/30 rounded-full h-3 overflow-hidden">
          <div 
            className="bg-white h-full rounded-full transition-all duration-500 ease-out" 
            style={{ width: `${xpProgress}%` }}
          />
        </div>
      </section>

      {/* Quick Tasks */}
      <section>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-lg font-bold text-slate-800">Tarefas Pendentes</h2>
          <span className="bg-blue-100 text-blue-600 px-2 py-0.5 rounded-full text-xs font-bold">
            {pendingTasks.length} total
          </span>
        </div>

        {pendingTasks.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-blue-100 rounded-2xl p-8 text-center">
            <p className="text-slate-400 text-sm">Tudo limpo por aqui! 🎉</p>
          </div>
        ) : (
          <div className="space-y-3">
            {pendingTasks.slice(0, 3).map(task => (
              <div key={task.id} className="bg-white p-4 rounded-2xl flex items-center justify-between border border-blue-50 shadow-sm">
                <div className="flex flex-col">
                  <span className="font-semibold text-slate-700">{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[10px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-bold">+{task.xp} XP</span>
                    <span className="text-[10px] bg-green-50 text-green-600 px-1.5 py-0.5 rounded font-bold">+{task.coins} 🪙</span>
                  </div>
                </div>
                <button 
                  onClick={() => onCompleteTask(task.id)}
                  className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center border border-blue-100 hover:bg-blue-100 transition-colors"
                >
                  ✓
                </button>
              </div>
            ))}
            {pendingTasks.length > 3 && (
              <p className="text-center text-xs text-blue-500 font-medium">E mais {pendingTasks.length - 3} tarefas...</p>
            )}
          </div>
        )}
      </section>

      {/* Recommended Rewards */}
      <section>
        <h2 className="text-lg font-bold text-slate-800 mb-4">Pode Comprar Agora</h2>
        {affordableRewards.length === 0 ? (
          <div className="bg-white rounded-2xl p-6 border border-green-50 text-center">
            <p className="text-slate-400 text-sm">Continue acumulando moedas! 💰</p>
          </div>
        ) : (
          <div className="flex gap-4 overflow-x-auto pb-4 -mx-2 px-2">
            {affordableRewards.map(reward => (
              <div key={reward.id} className="min-w-[160px] bg-white p-4 rounded-2xl border border-green-100 shadow-sm flex flex-col items-center">
                <span className="text-3xl mb-2">🎁</span>
                <span className="text-sm font-bold text-slate-700 text-center line-clamp-1">{reward.title}</span>
                <span className="text-xs font-bold text-green-600 mb-3">{reward.cost} 🪙</span>
                <button 
                  onClick={() => onPurchaseReward(reward.id)}
                  className="w-full py-1.5 bg-green-500 text-white text-[10px] font-bold rounded-lg uppercase tracking-wider hover:bg-green-600 transition-colors"
                >
                  Resgatar
                </button>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Task } from '../types';

interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);

  const addTask = () => {
    if (!newTitle.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      reminderSet: true
    };
    onUpdateTasks([newTask, ...tasks]);
    setNewTitle('');
    setShowAdd(false);
  };

  const removeTask = (id: string) => {
    onUpdateTasks(tasks.filter(t => t.id !== id));
  };

  const toggleTask = (id: string) => {
    onUpdateTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Minhas Tarefas</h2>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg shadow-blue-200"
        >
          +
        </button>
      </div>

      {showAdd && (
        <div className="mb-6 bg-white p-5 rounded-2xl border border-blue-200 shadow-xl animate-in slide-in-from-top duration-300">
          <h3 className="font-bold text-slate-700 mb-4">Nova Tarefa</h3>
          <input 
            type="text" 
            placeholder="O que você precisa fazer?"
            className="w-full border-b-2 border-blue-100 p-2 mb-4 focus:outline-none focus:border-blue-500 text-slate-700"
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
          />
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div>
              <label className="text-xs font-bold text-slate-400 block mb-1">RECOMPENSA XP</label>
              <input 
                type="number" 
                className="w-full bg-blue-50 p-2 rounded-lg border border-blue-100 text-blue-600 font-bold"
                value={newXp}
                onChange={(e) => setNewXp(parseInt(e.target.value) || 0)}
              />
            </div>
            <div>
              <label className="text-xs font-bold text-slate-400 block mb-1">MOEDAS</label>
              <input 
                type="number" 
                className="w-full bg-green-50 p-2 rounded-lg border border-green-100 text-green-600 font-bold"
                value={newCoins}
                onChange={(e) => setNewCoins(parseInt(e.target.value) || 0)}
              />
            </div>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={() => setShowAdd(false)}
              className="flex-1 py-3 text-slate-400 font-bold text-sm uppercase"
            >
              Cancelar
            </button>
            <button 
              onClick={addTask}
              className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm uppercase shadow-md"
            >
              Adicionar
            </button>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {tasks.length === 0 ? (
          <div className="text-center py-20 opacity-40">
            <span className="text-6xl block mb-4">📝</span>
            <p className="font-medium">Nenhuma tarefa agendada.</p>
          </div>
        ) : (
          tasks.map(task => (
            <div 
              key={task.id} 
              className={`bg-white p-4 rounded-2xl flex items-center gap-4 border shadow-sm transition-all ${
                task.completed ? 'opacity-50 border-slate-100' : 'border-blue-50'
              }`}
            >
              <button 
                onClick={() => toggleTask(task.id)}
                className={`w-6 h-6 rounded-md border-2 flex items-center justify-center ${
                  task.completed ? 'bg-green-500 border-green-500 text-white' : 'border-slate-200'
                }`}
              >
                {task.completed && '✓'}
              </button>
              <div className="flex-1 overflow-hidden">
                <span className={`block font-semibold text-slate-700 truncate ${task.completed ? 'line-through' : ''}`}>
                  {task.title}
                </span>
                <div className="flex gap-2">
                  <span className="text-[10px] text-blue-500 font-bold">{task.xp} XP</span>
                  <span className="text-[10px] text-green-500 font-bold">{task.coins} 🪙</span>
                </div>
              </div>
              <button 
                onClick={() => removeTask(task.id)}
                className="text-red-300 hover:text-red-500 transition-colors p-2"
              >
                🗑️
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TaskManager;

import React, { useState } from 'react';
import { Reward } from '../types';

interface RewardShopProps {
  rewards: Reward[];
  coins: number;
  onUpdateRewards: (rewards: Reward[]) => void;
  onPurchase: (id: string) => void;
}

const RewardShop: React.FC<RewardShopProps> = ({ rewards, coins, onUpdateRewards, onPurchase }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newCost, setNewCost] = useState(100);

  const addReward = () => {
    if (!newTitle.trim()) return;
    const newReward: Reward = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      cost: newCost,
      purchased: false,
      description: ''
    };
    onUpdateRewards([...rewards, newReward]);
    setNewTitle('');
    setShowAdd(false);
  };

  const removeReward = (id: string) => {
    onUpdateRewards(rewards.filter(r => r.id !== id));
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Loja de Prêmios</h2>
          <p className="text-sm text-green-600 font-bold">Saldo: {coins} 🪙</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-green-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg shadow-green-200"
        >
          +
        </button>
      </div>

      {showAdd && (
        <div className="mb-6 bg-white p-5 rounded-2xl border border-green-200 shadow-xl">
          <h3 className="font-bold text-slate-700 mb-4">Nova Recompensa</h3>
          <input 
            type="text" 
            placeholder="Ex: Comer um chocolate, 1h de game..."
            className="w-full border-b-2 border-green-100 p-2 mb-4 focus:outline-none focus:border-green-500 text-slate-700"
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
          />
          <div className="mb-6">
            <label className="text-xs font-bold text-slate-400 block mb-1">CUSTO EM MOEDAS</label>
            <input 
              type="number" 
              className="w-full bg-green-50 p-2 rounded-lg border border-green-100 text-green-600 font-bold"
              value={newCost}
              onChange={(e) => setNewCost(parseInt(e.target.value) || 0)}
            />
          </div>
          <div className="flex gap-2">
            <button 
              onClick={() => setShowAdd(false)}
              className="flex-1 py-3 text-slate-400 font-bold text-sm uppercase"
            >
              Cancelar
            </button>
            <button 
              onClick={addReward}
              className="flex-1 py-3 bg-green-600 text-white rounded-xl font-bold text-sm uppercase shadow-md"
            >
              Criar
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-2 gap-4">
        {rewards.length === 0 ? (
          <div className="col-span-2 text-center py-20 opacity-40">
            <span className="text-6xl block mb-4">🎁</span>
            <p className="font-medium">Cadastre suas recompensas!</p>
          </div>
        ) : (
          rewards.map(reward => {
            const canAfford = coins >= reward.cost;
            return (
              <div key={reward.id} className="bg-white p-4 rounded-3xl border border-green-50 shadow-sm flex flex-col items-center relative group">
                <button 
                  onClick={() => removeReward(reward.id)}
                  className="absolute top-2 right-2 text-slate-300 hover:text-red-400 text-xs"
                >
                  ✕
                </button>
                <div className="w-16 h-16 bg-green-50 rounded-full flex items-center justify-center text-3xl mb-3">
                  🎁
                </div>
                <h4 className="font-bold text-slate-700 text-center text-sm line-clamp-2 mb-1">{reward.title}</h4>
                <div className="flex items-center gap-1 mb-4">
                  <span className="text-xs font-bold text-green-600">{reward.cost} Moedas</span>
                </div>
                <button 
                  disabled={!canAfford}
                  onClick={() => onPurchase(reward.id)}
                  className={`w-full py-2 rounded-xl text-xs font-bold uppercase tracking-wider transition-all ${
                    canAfford 
                    ? 'bg-green-600 text-white shadow-md shadow-green-100 hover:scale-105 active:scale-95' 
                    : 'bg-slate-100 text-slate-400 cursor-not-allowed'
                  }`}
                >
                  {canAfford ? 'Resgatar' : 'Faltam Moedas'}
                </button>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default RewardShop;

import React from 'react';
import { AppData } from '../types';

interface SettingsProps {
  data: AppData;
  onImport: (data: AppData) => void;
}

const Settings: React.FC<SettingsProps> = ({ data, onImport }) => {
  const exportBackup = () => {
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `gami_routine_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importBackup = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const importedData = JSON.parse(e.target?.result as string);
        if (importedData.stats && importedData.tasks) {
          onImport(importedData);
          alert('Backup importado com sucesso!');
        } else {
          throw new Error('Formato inválido');
        }
      } catch (err) {
        alert('Erro ao importar backup. Verifique o arquivo JSON.');
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold text-slate-800 mb-6">Configurações</h2>

      <div className="space-y-6">
        <section className="bg-white p-6 rounded-3xl border border-blue-50 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
            <span>💾</span> Dados e Backup
          </h3>
          <p className="text-sm text-slate-500 mb-6 leading-relaxed">
            Seus dados são salvos localmente. Use as funções abaixo para exportar seu progresso ou mover para outro dispositivo.
          </p>

          <div className="space-y-3">
            <button 
              onClick={exportBackup}
              className="w-full py-4 bg-blue-50 text-blue-600 rounded-2xl font-bold text-sm uppercase tracking-wide border border-blue-100 flex items-center justify-center gap-2 hover:bg-blue-100 transition-colors"
            >
              <span>📤</span> Exportar Backup (JSON)
            </button>

            <div className="relative">
              <input 
                type="file" 
                accept=".json" 
                onChange={importBackup}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
              <button className="w-full py-4 bg-green-50 text-green-600 rounded-2xl font-bold text-sm uppercase tracking-wide border border-green-100 flex items-center justify-center gap-2 pointer-events-none">
                <span>📥</span> Importar Backup
              </button>
            </div>
          </div>
        </section>

        <section className="bg-white p-6 rounded-3xl border border-blue-50 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-4">Sobre o GamiRoutine</h3>
          <div className="space-y-4 text-sm text-slate-500">
            <div className="flex justify-between border-b border-slate-50 pb-2">
