interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]); // Padrão: dias úteis
  const [reminderTime, setReminderTime] = useState('09:00');

  const daysOfWeek = [
    { id: 0, label: 'D' },
    { id: 1, label: 'S' },
    { id: 2, label: 'T' },
    { id: 3, label: 'Q' },
    { id: 4, label: 'Q' },
    { id: 5, label: 'S' },
    { id: 6, label: 'S' }
  ];

  const toggleDay = (dayId: number) => {
    setSelectedDays(prev => 
      prev.includes(dayId) ? prev.filter(d => d !== dayId) : [...prev, dayId]
    );
  };

  const addTask = () => {
    if (!newTitle.trim()) return;
    if (selectedDays.length === 0) {
      alert("Selecione pelo menos um dia da semana!");
      return;
    }

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      recurringDays: selectedDays,
      reminderTime: reminderTime
    };
    onUpdateTasks([newTask, ...tasks]);
    setNewTitle('');
    setShowAdd(false);
  };

  const removeTask = (id: string) => {
    onUpdateTasks(tasks.filter(t => t.id !== id));
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Minhas Missões</h2>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg shadow-blue-200"
        >
          +
        </button>
      </div>

      {showAdd && (
        <div className="mb-6 bg-white p-5 rounded-2xl border border-blue-200 shadow-xl animate-in slide-in-from-top duration-300">
          <h3 className="font-bold text-slate-700 mb-4">Nova Missão Recorrente</h3>

          <div className="space-y-4">
            <div>
              <label className="text-xs font-bold text-slate-400 block mb-1">TÍTULO</label>
              <input 
                type="text" 
                placeholder="Ex: Ler 10 páginas, Academia..."
                className="w-full border-b-2 border-blue-100 p-2 focus:outline-none focus:border-blue-500 text-slate-700"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
              />
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 block mb-2">DIAS DA SEMANA</label>
              <div className="flex justify-between">
                {daysOfWeek.map(day => (
                  <button
                    key={day.id}
                    onClick={() => toggleDay(day.id)}
                    className={`w-9 h-9 rounded-full text-xs font-bold transition-all ${
                      selectedDays.includes(day.id) 
                      ? 'bg-blue-600 text-white shadow-md' 
                      : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                    }`}
                  >
                    {day.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-bold text-slate-400 block mb-1">HORÁRIO ALERTA</label>
                <input 
                  type="time" 
                  className="w-full bg-slate-50 p-2 rounded-lg border border-slate-100 text-slate-600 font-bold"
                  value={reminderTime}
                  onChange={(e) => setReminderTime(e.target.value)}
                />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-400 block mb-1">MOEDAS</label>
                <input 
                  type="number" 
                  className="w-full bg-green-50 p-2 rounded-lg border border-green-100 text-green-600 font-bold"
                  value={newCoins}
                  onChange={(e) => setNewCoins(parseInt(e.target.value) || 0)}
                />
              </div>
            </div>

            <div className="flex gap-2 pt-2">
              <button 
                onClick={() => setShowAdd(false)}
                className="flex-1 py-3 text-slate-400 font-bold text-sm uppercase"
              >
                Cancelar
              </button>
              <button 
                onClick={addTask}
                className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm uppercase shadow-md active:scale-95 transition-transform"
              >
                Criar Hábito
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {tasks.length === 0 ? (
          <div className="text-center py-20 opacity-40">
            <span className="text-6xl block mb-4">🗓️</span>
            <p className="font-medium">Cadastre seus primeiros hábitos.</p>
          </div>
        ) : (
          tasks.map(task => (
            <div key={task.id} className="bg-white p-4 rounded-2xl border border-blue-50 shadow-sm flex items-center gap-4">
              <div className="flex-1 min-w-0">
                <span className="block font-semibold text-slate-700 truncate">{task.title}</span>
                <div className="flex flex-wrap gap-1 mt-1">
                  {daysOfWeek.map(d => (
                    <span 
                      key={d.id} 
                      className={`text-[8px] px-1 rounded-sm font-bold ${
                        task.recurringDays.includes(d.id) ? 'bg-blue-100 text-blue-600' : 'bg-slate-50 text-slate-300'
