import { View, Task, Reward, Punishment, UserStats, AppData } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  stats: {
    totalXp: 0,
    totalCoins: 0,
    level: 1
  },
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Lógica de reset diário
      const today = new Date().toISOString().split('T')[0];
      parsed.tasks = parsed.tasks.map((t: Task) => {
        if (t.completed && t.lastCompletedDate !== today && t.recurringDays.length > 0) {
          return { ...t, completed: false };
        }
        return t;
      });
      // Fallback para campos novos caso o usuário já tenha dados antigos
      if (!parsed.punishments) parsed.punishments = [];
      if (!parsed.dailyReviewTime) parsed.dailyReviewTime = '21:00';
      return parsed;
    }
    return INITIAL_DATA;
  });

  const notifiedTasks = useRef<Set<string>>(new Set());

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      const currentDay = now.getDay();
      const todayStr = now.toISOString().split('T')[0];

      // Lembretes de Tarefas
      data.tasks.forEach(task => {
        if (!task.completed && task.reminderTime === currentTime && task.recurringDays.includes(currentDay)) {
          const key = `task-${task.id}-${todayStr}-${task.reminderTime}`;
          if (!notifiedTasks.current.has(key)) {
            sendNotification(`Missão: ${task.title}`, `Não esqueça de ganhar seu XP de hoje!`);
            notifiedTasks.current.add(key);
          }
        }
      });

      // Lembrete de Revisão Diária
      if (data.dailyReviewTime === currentTime) {
        const key = `review-${todayStr}-${data.dailyReviewTime}`;
        if (!notifiedTasks.current.has(key)) {
          sendNotification(`Hora da Revisão!`, `Abra o app para marcar suas missões e revisar o dia.`);
          notifiedTasks.current.add(key);
        }
      }
    };

    const sendNotification = (title: string, body: string) => {
      if (Notification.permission === 'granted') {
        new Notification(title, { body, icon: 'https://cdn-icons-png.flaticon.com/512/3112/3112946.png' });
      } else {
        alert(`⏰ ${title.toUpperCase()}\n${body}`);
      }
    };

    const interval = setInterval(checkReminders, 30000);
    return () => clearInterval(interval);
  }, [data.tasks, data.dailyReviewTime]);

  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  const updateData = (newData: Partial<AppData>) => {
    setData(prev => ({ ...prev, ...newData }));
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today } : t
    );

    const newXp = data.stats.totalXp + task.xp;
    const newCoins = data.stats.totalCoins + task.coins;
    const newLevel = Math.floor(newXp / 1000) + 1;

    updateData({
      tasks: newTasks,
      stats: { ...data.stats, totalXp: newXp, totalCoins: newCoins, level: newLevel }
    });
  };

  const applyPunishment = (punishmentId: string) => {
    const punishment = data.punishments.find(p => p.id === punishmentId);
    if (!punishment) return;

    // Garante que o saldo não fique negativo (opcional, mas recomendado)
    const newCoins = Math.max(0, data.stats.totalCoins - punishment.cost);

    updateData({
      stats: { ...data.stats, totalCoins: newCoins }
    });
    alert(`Punição aplicada: -${punishment.cost} moedas.`);
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard stats={data.stats} tasks={data.tasks} rewards={data.rewards} onCompleteTask={handleCompleteTask} onPurchaseReward={(id) => {
          const reward = data.rewards.find(r => r.id === id);
          if (reward && data.stats.totalCoins >= reward.cost) {
            updateData({
              rewards: data.rewards.filter(r => r.id !== id),
              stats: { ...data.stats, totalCoins: data.stats.totalCoins - reward.cost }
            });
          }
        }} />;
      case 'tasks':
        return <TaskManager tasks={data.tasks} onUpdateTasks={(tasks) => updateData({ tasks })} />;
      case 'shop':
        return <RewardShop rewards={data.rewards} coins={data.stats.totalCoins} onUpdateRewards={(rewards) => updateData({ rewards })} onPurchase={(id) => {
          const reward = data.rewards.find(r => r.id === id);
          if (reward && data.stats.totalCoins >= reward.cost) {
            updateData({
              rewards: data.rewards.filter(r => r.id !== id),
              stats: { ...data.stats, totalCoins: data.stats.totalCoins - reward.cost }
            });
          }
        }} />;
      case 'punishments':
        return <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => updateData({ punishments })} onApply={applyPunishment} />;
      case 'settings':
        return <Settings data={data} onImport={setData} onUpdateTime={(time) => updateData({ dailyReviewTime: time })} />;
      default:
        return <Dashboard stats={data.stats} tasks={data.tasks} rewards={data.rewards} onCompleteTask={handleCompleteTask} onPurchaseReward={() => {}} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-xs text-slate-400 font-medium">Nível {data.stats.level}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center bg-blue-50 px-3 py-1 rounded-full border border-blue-200">
                <span className="text-sm font-bold text-blue-600 mr-1">✨</span>
                <span className="text-sm font-bold text-blue-600">{data.stats.totalXp}</span>
            </div>
            <div className="flex items-center bg-green-50 px-3 py-1 rounded-full border border-green-200">
                <span className="text-sm font-bold text-green-600 mr-1">🪙</span>
                <span className="text-sm font-bold text-green-600">{data.stats.totalCoins}</span>
            </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto pb-24">
        {renderView()}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

