import React from 'react';
import { HistoryEntry } from '../types';

interface HistoryManagerProps {
  history: HistoryEntry[];
}

const HistoryManager: React.FC<HistoryManagerProps> = ({ history }) => {
  const formatDate = (isoDate: string) => {
    const d = new Date(isoDate);
    return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  const getEntryStyles = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'task': return { icon: '✅', color: 'text-blue-600', bg: 'bg-blue-50', label: '+ XP' };
      case 'reward': return { icon: '🎁', color: 'text-green-600', bg: 'bg-green-50', label: '- Moedas' };
      case 'punishment': return { icon: '⚠️', color: 'text-red-600', bg: 'bg-red-50', label: '- Moedas' };
    }
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Histórico de Jornada</h2>
        <p className="text-sm text-slate-400">Suas vitórias e aprendizados registrados</p>
      </div>

      <div className="space-y-4">
        {history.length === 0 ? (
          <div className="text-center py-20 opacity-40">
            <span className="text-6xl block mb-4">📜</span>
            <p className="font-medium">O pergaminho está em branco...</p>
          </div>
        ) : (
          history.map(entry => {
            const styles = getEntryStyles(entry.type);
            return (
              <div key={entry.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 transition-all active:scale-95">
                <div className={`w-12 h-12 ${styles.bg} rounded-full flex items-center justify-center text-xl`}>
                  {styles.icon}
                </div>
                <div className="flex-1 min-w-0">
                  <span className="block font-bold text-slate-700 truncate">{entry.title}</span>
                  <span className="text-[10px] text-slate-400">{formatDate(entry.date)}</span>
                </div>
                <div className="text-right">
                  <span className={`block font-bold text-sm ${styles.color}`}>
                    {entry.type === 'task' ? '+' : '-'}{entry.value}
                  </span>
                  <span className="text-[8px] uppercase font-black text-slate-300 tracking-tighter">{styles.label}</span>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

