  title: string;
  xp: number;
  coins: number;
  completed: boolean;
  type: 'recurring' | 'one-time'; // Novo campo
  recurringDays: number[]; // 0 = Domingo, 1 = Segunda, etc.
  reminderTime?: string;   
  lastCompletedDate?: string; 
}

export interface Reward {
  id: string;
  title: string;
  cost: number;
