}

export interface Punishment {
  id: string;
  title: string;
  cost: number;
}

export interface HistoryEntry {
  id: string;
  type: 'task' | 'reward' | 'punishment';
  title: string;
  value: number;
  xpValue?: number; // Guardar XP separadamente para reversão precisa
  date: string; 
  relatedId?: string; // ID da tarefa original para reverter status 'completed'
}

export interface UserStats {
  totalXp: number;
  totalCoins: number;
  level: number;
}

export interface AppData {
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
