  dailyReviewTime: string; 
}

export type View = 'dashboard' | 'tasks' | 'shop' | 'punishments' | 'history' | 'settings';

import React, { useState, useEffect, useRef } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, UserStats, AppData } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalXp: 0,
    totalCoins: 0,
    level: 1
  },
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      // Reset diário: Apenas para recorrentes
      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        return t;
      });

      if (!parsed.punishments) parsed.punishments = [];
      if (!parsed.history) parsed.history = [];
      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, xpValue: number = 0, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      xpValue,
      date: new Date().toISOString(),
      relatedId
    };
    return [entry, ...data.history];
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;

    if (!confirm('Deseja excluir este registro e reverter a pontuação?')) return;

    let newXp = data.stats.totalXp;
    let newCoins = data.stats.totalCoins;
    let newTasks = [...data.tasks];

    // Reverter pontuações
    if (entry.type === 'task') {
      newXp -= (entry.xpValue || 0);
      newCoins -= entry.value;
      // Se era uma tarefa pontual, marcar como não concluída novamente
      if (entry.relatedId) {
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false } : t);
      }
    } else if (entry.type === 'reward' || entry.type === 'punishment') {
      newCoins += entry.value;
    }

    const newLevel = Math.max(1, Math.floor(newXp / 1000) + 1);

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      stats: {
        ...prev.stats,
        totalXp: Math.max(0, newXp),
        totalCoins: Math.max(0, newCoins),
        level: newLevel
      }
    }));
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today } : t
    );

    const newXp = data.stats.totalXp + task.xp;
    const newCoins = data.stats.totalCoins + task.coins;
    const newLevel = Math.floor(newXp / 1000) + 1;

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: addHistoryEntry('task', task.title, task.coins, task.xp, task.id),
      stats: { ...prev.stats, totalXp: newXp, totalCoins: newCoins, level: newLevel }
    }));
  };

  const applyPunishment = (punishmentId: string) => {
    const punishment = data.punishments.find(p => p.id === punishmentId);
    if (!punishment) return;

    const newCoins = Math.max(0, data.stats.totalCoins - punishment.cost);

    setData(prev => ({
      ...prev,
      history: addHistoryEntry('punishment', punishment.title, punishment.cost),
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handlePurchaseReward = (rewardId: string) => {
    const reward = data.rewards.find(r => r.id === rewardId);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    setData(prev => ({
      ...prev,
      history: addHistoryEntry('reward', reward.title, reward.cost),
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-xs text-slate-400 font-medium">Nível {data.stats.level}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center bg-blue-50 px-3 py-1 rounded-full border border-blue-200">
                <span className="text-sm font-bold text-blue-600 mr-1">✨</span>
                <span className="text-sm font-bold text-blue-600">{data.stats.totalXp}</span>
            </div>
            <div className="flex items-center bg-green-50 px-3 py-1 rounded-full border border-green-200">
                <span className="text-sm font-bold text-green-600 mr-1">🪙</span>
                <span className="text-sm font-bold text-green-600">{data.stats.totalCoins}</span>
            </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && <Dashboard stats={data.stats} tasks={data.tasks} rewards={data.rewards} punishments={data.punishments} onCompleteTask={handleCompleteTask} onPurchaseReward={handlePurchaseReward} onApplyPunishment={applyPunishment} />}
        {currentView === 'tasks' && <TaskManager tasks={data.tasks} onUpdateTasks={(tasks) => setData({...data, tasks})} />}
        {currentView === 'shop' && <RewardShop rewards={data.rewards} coins={data.stats.totalCoins} onUpdateRewards={(rewards) => setData({...data, rewards})} onPurchase={handlePurchaseReward} />}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={applyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, onCompleteTask, onPurchaseReward, onApplyPunishment }) => {
