        <div className="flex justify-between items-end mb-3">
          <span className="text-3xl font-bold">Nível {stats.level}</span>
          <span className="text-blue-100 text-sm font-medium">{stats.totalXp % 1000} / 1000 XP</span>
        </div>
        <div className="w-full bg-blue-700/30 rounded-full h-3 overflow-hidden">
          <div 
            className="bg-white h-full rounded-full transition-all duration-500 ease-out" 
            style={{ width: `${xpProgress}%` }}
          />
        </div>
      </section>

      {/* Missões do Dia */}
