import React from 'react';
import { HistoryEntry } from '../types';

interface HistoryManagerProps {
  history: HistoryEntry[];
  onDeleteEntry: (id: string) => void;
}

const HistoryManager: React.FC<HistoryManagerProps> = ({ history, onDeleteEntry }) => {
  const formatDate = (isoDate: string) => {
    const d = new Date(isoDate);
    return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  const getEntryStyles = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'task': return { icon: '✅', color: 'text-blue-600', bg: 'bg-blue-50', label: 'Ganho' };
      case 'reward': return { icon: '🎁', color: 'text-green-600', bg: 'bg-green-50', label: 'Gasto' };
      case 'punishment': return { icon: '⚠️', color: 'text-red-600', bg: 'bg-red-50', label: 'Perda' };
    }
  };

  return (
    <div className="p-6">
      <div className="mb-6 flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Histórico</h2>
          <p className="text-sm text-slate-400">Arrependeu-se? Apague para estornar.</p>
        </div>
      </div>

      <div className="space-y-4">
        {history.length === 0 ? (
          <div className="text-center py-20 opacity-40">
            <span className="text-6xl block mb-4">📜</span>
            <p className="font-medium">Nenhum rastro encontrado...</p>
          </div>
        ) : (
          history.map(entry => {
            const styles = getEntryStyles(entry.type);
            return (
              <div key={entry.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                <div className={`w-10 h-10 ${styles.bg} rounded-full flex items-center justify-center text-lg`}>
                  {styles.icon}
                </div>
                <div className="flex-1 min-w-0">
                  <span className="block font-bold text-slate-700 truncate text-sm">{entry.title}</span>
                  <span className="text-[9px] text-slate-400">{formatDate(entry.date)}</span>
                </div>
                <div className="text-right flex items-center gap-3">
                  <div>
                    <span className={`block font-black text-xs ${styles.color}`}>
                      {entry.type === 'task' ? '+' : '-'}{entry.value} 🪙
                    </span>
                    {entry.xpValue ? <span className="text-[8px] text-blue-400 font-bold">+{entry.xpValue} XP</span> : null}
                  </div>
                  <button 
                    onClick={() => onDeleteEntry(entry.id)}
                    className="w-8 h-8 flex items-center justify-center text-red-300 hover:text-red-600 hover:bg-red-50 rounded-full transition-all"
                    title="Excluir e Estornar"
