export type View = 'dashboard' | 'tasks' | 'shop' | 'punishments' | 'history' | 'settings';

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'bonus' || entry.type === 'reward' || entry.type === 'punishment') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else newCoins += entry.value;
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: Math.max(0, newCoins) }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    setData({ ...data, currentSeason: season });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);
    setData({ ...data, currentSeason: null });
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Temporada 2025</p>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center bg-green-50 px-3 py-1 rounded-full border border-green-200">
                <span className="text-sm font-bold text-green-600 mr-1">🪙</span>
                <span className="text-sm font-bold text-green-600">{data.stats.totalCoins}</span>
            </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={(id) => {
              const reward = data.rewards.find(r => r.id === id);
              if (reward && data.stats.totalCoins >= reward.cost) {
                setData(prev => ({
                  ...prev,
                  history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
                  stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
                }));
              }
            }}
            onApplyPunishment={(id) => {
              const pun = data.punishments.find(p => p.id === id);
              if (pun) {
                setData(prev => ({
                  ...prev,
                  history: [addHistoryEntry('punishment', pun.title, pun.cost), ...prev.history],
                  stats: { ...prev.stats, totalCoins: Math.max(0, prev.stats.totalCoins - pun.cost) }
                }));
              }
            }}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && <TaskManager tasks={data.tasks} onUpdateTasks={(tasks) => setData({...data, tasks})} />}
        {currentView === 'shop' && <RewardShop rewards={data.rewards} coins={data.stats.totalCoins} onUpdateRewards={(rewards) => setData({...data, rewards})} onPurchase={(id) => {}} />}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={(id) => {}} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  // Dados de criação de temporada
  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const currentDay = new Date().getDay();
  const today = new Date();

  // Rotina: Recorrentes do dia
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  // Pontuais: Não recorrentes e não concluídas
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6">
      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nenhuma Temporada Ativa</h3>
          <div className="space-y-3">
            <input 
              placeholder="Nome da Temporada" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm"
              value={newSName} onChange={e => setNewSName(e.target.value)}
            />
            <input 
              type="number" placeholder="Meta de Pontos" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm"
              value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value))}
            />
            <input 
              placeholder="Prêmio Final (Ex: Uma viagem)" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm"
              value={newSReward} onChange={e => setNewSReward(e.target.value)}
            />
            <button onClick={createSeason} className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg">Começar Jornada</button>
          </div>
        </section>
      ) : (
        <section className="bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-xl">
          <div className="flex justify-between items-start mb-4">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest">Temporada Atual</p>
              <h3 className="text-xl font-bold">{season.title}</h3>
            </div>
            {isSeasonExpired && (
              <button 
                onClick={onEndSeason}
                className="bg-yellow-400 text-blue-900 px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-lg animate-bounce"
              >
                Encerrar Temporada
              </button>
            )}
          </div>

          <div className="mb-4">
            <div className="flex justify-between text-[10px] font-bold mb-1 uppercase opacity-80">
              <span>{season.currentPoints} Pontos</span>
              <span>Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-blue-900/30 rounded-full h-3">
              <div className="bg-yellow-400 h-full rounded-full transition-all duration-700" style={{ width: `${getSeasonProgress()}%` }} />
            </div>
            <p className="text-[9px] mt-2 italic opacity-70 text-center">Fim em: {new Date(season.endDate).toLocaleDateString()}</p>
          </div>

          <div className="bg-white/10 p-3 rounded-2xl">
            <p className="text-[10px] font-bold uppercase opacity-70 mb-1">Prêmio Final</p>
            <p className="font-bold text-sm">🎁 {season.reward}</p>
          </div>
        </section>
      )}

      {/* Missões de Rotina */}
      <section>
        <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
          <span>📅</span> Missões de Rotina
        </h2>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Tudo limpo por aqui hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50 border-slate-100' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3">
        {/* Missões Pontuais Ocultas */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/50">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais ({oneTimeTasks.length})</span>
            </div>
            <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center">Nenhuma pendência pontual.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Falhas Ocultas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/50">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚠️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falha</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.map(p => (
                <div key={p.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-xl">
                  <span className="text-xs font-bold text-slate-700">{p.title}</span>
                  <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-500 text-white px-3 py-1 rounded-lg text-[10px] font-bold uppercase">Falhei (-{p.cost} 🪙)</button>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Loja Oculta */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/50">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎁</span>
              <span className="font-bold text-green-800 text-sm">Resgatar Prêmios</span>
            </div>
            <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {rewards.map(r => (
                <div key={r.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-xl">
                  <span className="text-xs font-bold text-slate-700">{r.title} ({r.cost} 🪙)</span>
                  <button 
                    disabled={stats.totalCoins < r.cost}
                    onClick={() => onPurchaseReward(r.id)} 
                    className={`px-3 py-1 rounded-lg text-[10px] font-bold ${stats.totalCoins >= r.cost ? 'bg-green-600 text-white' : 'bg-slate-200 text-slate-400'}`}
                  >
                    Resgatar
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { HistoryEntry } from '../types';

interface HistoryManagerProps {
  history: HistoryEntry[];
  onDeleteEntry: (id: string) => void;
}

const HistoryManager: React.FC<HistoryManagerProps> = ({ history, onDeleteEntry }) => {
  const formatDate = (isoDate: string) => {
    const d = new Date(isoDate);
    return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  };

  const getEntryStyles = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'task': return { icon: '✅', color: 'text-blue-600', bg: 'bg-blue-50', label: 'Pontos' };
      case 'reward': return { icon: '🎁', color: 'text-green-600', bg: 'bg-green-50', label: 'Gasto' };
      case 'punishment': return { icon: '⚠️', color: 'text-red-600', bg: 'bg-red-50', label: 'Perda' };
      case 'bonus': return { icon: '🔥', color: 'text-yellow-600', bg: 'bg-yellow-50', label: 'Bônus' };
    }
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold text-slate-800 mb-6">Jornada</h2>
      <div className="space-y-4">
        {history.length === 0 ? (
          <p className="text-center py-20 opacity-40">O pergaminho está vazio.</p>
        ) : (
          history.map(entry => {
            const s = getEntryStyles(entry.type);
            return (
              <div key={entry.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
                <div className={`w-10 h-10 ${s.bg} rounded-full flex items-center justify-center text-lg`}>{s.icon}</div>
                <div className="flex-1 min-w-0">
                  <span className="block font-bold text-slate-700 truncate text-sm">{entry.title}</span>
                  <span className="text-[9px] text-slate-400">{formatDate(entry.date)}</span>
                </div>
                <div className="text-right flex items-center gap-2">
                  <span className={`font-black text-xs ${s.color}`}>
                    {entry.type === 'task' || entry.type === 'bonus' ? '+' : '-'}{entry.value}
                  </span>
                  <button onClick={() => onDeleteEntry(entry.id)} className="text-red-200 hover:text-red-400 p-1">✕</button>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

export default HistoryManager;

import React, { useState } from 'react';
import { Task } from '../types';

interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);
  const [taskType, setTaskType] = useState<'recurring' | 'one-time'>('recurring');
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]); 
  const [reminderTime, setReminderTime] = useState('09:00');

  const daysOfWeek = [
    { id: 0, label: 'D' }, { id: 1, label: 'S' }, { id: 2, label: 'T' }, 
    { id: 3, label: 'Q' }, { id: 4, label: 'Q' }, { id: 5, label: 'S' }, { id: 6, label: 'S' }
  ];

  const addTask = () => {
    if (!newTitle.trim()) return;
    if (taskType === 'recurring' && selectedDays.length === 0) {
      alert("Selecione os dias para missões diárias!");
      return;
    }

    // Added completionCount: 0 to satisfy the Task interface requirement
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      type: taskType,
      recurringDays: taskType === 'recurring' ? selectedDays : [],
      reminderTime: reminderTime,
      completionCount: 0
    };
    onUpdateTasks([newTask, ...tasks]);
    setNewTitle('');
    setShowAdd(false);
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Missões</h2>
        <button onClick={() => setShowAdd(true)} className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg">+</button>
      </div>

      {showAdd && (
        <div className="mb-6 bg-white p-5 rounded-2xl border border-blue-200 shadow-xl">
          <h3 className="font-bold text-slate-700 mb-4 text-sm">Configurar Nova Missão</h3>

          <div className="space-y-4">
            {/* Seletor de Tipo */}
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <button 
                onClick={() => setTaskType('recurring')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${taskType === 'recurring' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
              >
                Diária (Hábito)
              </button>
              <button 
                onClick={() => setTaskType('one-time')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${taskType === 'one-time' ? 'bg-white text-purple-600 shadow-sm' : 'text-slate-400'}`}
              >
                Pontual (Tarefa)
              </button>
            </div>

            <input 
              type="text" 
              placeholder="O que precisa ser feito?"
              className="w-full border-b-2 border-blue-100 p-2 focus:outline-none focus:border-blue-500 text-slate-700"
              value={newTitle}
              onChange={(e) => setNewTitle(e.target.value)}
            />

            {taskType === 'recurring' && (
              <div>
                <label className="text-[10px] font-black text-slate-400 block mb-2 uppercase">Repetir nos dias:</label>
                <div className="flex justify-between">
                  {daysOfWeek.map(day => (
                    <button
                      key={day.id}
                      onClick={() => setSelectedDays(prev => prev.includes(day.id) ? prev.filter(d => d !== day.id) : [...prev, day.id])}
                      className={`w-8 h-8 rounded-full text-[10px] font-bold transition-all ${selectedDays.includes(day.id) ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                    >
                      {day.label}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="grid grid-cols-3 gap-3">
              <div className="col-span-1">
                <label className="text-[10px] font-black text-slate-400 block mb-1 uppercase">XP</label>
                <input type="number" className="w-full bg-blue-50 p-2 rounded-lg text-xs font-bold" value={newXp} onChange={e => setNewXp(parseInt(e.target.value))} />
              </div>
              <div className="col-span-1">
                <label className="text-[10px] font-black text-slate-400 block mb-1 uppercase">🪙</label>
                <input type="number" className="w-full bg-green-50 p-2 rounded-lg text-xs font-bold" value={newCoins} onChange={e => setNewCoins(parseInt(e.target.value))} />
              </div>
              <div className="col-span-1">
                <label className="text-[10px] font-black text-slate-400 block mb-1 uppercase">Hora</label>
                <input type="time" className="w-full bg-slate-50 p-2 rounded-lg text-xs font-bold" value={reminderTime} onChange={e => setReminderTime(e.target.value)} />
              </div>
            </div>

            <div className="flex gap-2 pt-2">
              <button onClick={() => setShowAdd(false)} className="flex-1 py-3 text-slate-400 font-bold text-xs uppercase">Cancelar</button>
              <button onClick={addTask} className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold text-xs uppercase shadow-md">Salvar</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {tasks.map(task => (
          <div key={task.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
            <div className="flex-1 min-w-0 pr-4">
              <span className="block font-bold text-slate-700 truncate">{task.title}</span>
              <div className="flex items-center gap-2 mt-1">
                <span className={`text-[8px] px-1 rounded font-black uppercase ${task.type === 'one-time' ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'}`}>
                  {task.type === 'one-time' ? 'Pontual' : 'Diária'}
                </span>
                <span className="text-[9px] text-slate-400 font-medium italic">⏰ {task.reminderTime}</span>
              </div>
            </div>
            <button onClick={() => onUpdateTasks(tasks.filter(t => t.id !== task.id))} className="text-red-200 hover:text-red-500 p-2">🗑️</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TaskManager;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const currentDay = new Date().getDay();

  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6">
      {/* Season Card - Simplificado */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3">
            <input 
              placeholder="Título da Season" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSName} onChange={e => setNewSName(e.target.value)}
            />
            <input 
              type="number" placeholder="Objetivo de Pontos" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value))}
            />
            <input 
              placeholder="Prêmio (Ficará oculto)" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSReward} onChange={e => setNewSReward(e.target.value)}
            />
            <button onClick={createSeason} className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className="bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-xl">
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Season</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
            </div>
            {isSeasonExpired && (
              <button 
                onClick={onEndSeason}
                className="bg-yellow-400 text-blue-900 px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-lg animate-pulse"
              >
                Encerrar
              </button>
            )}
          </div>

          <div className="space-y-2">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts acumulados</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-blue-900/40 rounded-full h-4 p-1 overflow-hidden">
              <div 
                className="bg-yellow-400 h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(250,204,21,0.5)]" 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
            <p className="text-[10px] opacity-60 text-right italic font-medium">Progressão: {Math.round(getSeasonProgress())}%</p>
          </div>
        </section>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina de Hoje
            </h2>
            <span className="text-[10px] font-bold text-slate-400 uppercase">{new Date().toLocaleDateString('pt-BR', { weekday: 'long' })}</span>
        </div>

        {routineTasks.length === 0 ? (
          <div className="bg-white p-6 rounded-2xl border border-blue-50 text-center">
            <p className="text-xs text-slate-400">Nenhuma rotina para este dia.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50 border-slate-100' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold active:bg-blue-600 active:text-white transition-colors">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Seções Ocultas */}
      <div className="space-y-3 pb-4">
        {/* Missões Pontuais */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/30">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Nenhuma pendência pontual.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold shadow-sm">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Falhas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/30">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚠️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falha</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições configuradas.</p> : punishments.map(p => (
                <div key={p.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-700">{p.title}</span>
                  <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-500 text-white px-3 py-1 rounded-lg text-[10px] font-bold uppercase shadow-sm">Falhei (-{p.cost} 🪙)</button>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Loja */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/30">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎁</span>
              <span className="font-bold text-green-800 text-sm">Resgatar Prêmios</span>
            </div>
            <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {rewards.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Loja vazia.</p> : rewards.map(r => (
                <div key={r.id} className="flex items-center justify-between p-2 bg-slate-50 rounded-xl border border-slate-100">
                  <span className="text-xs font-bold text-slate-700">{r.title} ({r.cost} 🪙)</span>
                  <button 
                    disabled={stats.totalCoins < r.cost}
                    onClick={() => onPurchaseReward(r.id)} 
                    className={`px-3 py-1 rounded-lg text-[10px] font-bold shadow-sm ${stats.totalCoins >= r.cost ? 'bg-green-600 text-white' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
                  >
                    Resgatar
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

