import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    // Prêmios agora geram 10 pontos na season
    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'bonus' || entry.type === 'reward' || entry.type === 'punishment') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10; // Estorna bônus de prêmio
      }
      else newCoins += entry.value;
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: Math.max(0, newCoins) }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    setData({ ...data, currentSeason: season });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);
    setData({ ...data, currentSeason: null });
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Temporada {new Date().getFullYear()}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className="flex items-center bg-green-50 px-3 py-1 rounded-full border border-green-200">
                <span className="text-sm font-bold text-green-600 mr-1">🪙</span>
                <span className="text-sm font-bold text-green-600">{data.stats.totalCoins}</span>
            </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={(id) => {
              const pun = data.punishments.find(p => p.id === id);
              if (pun) {
                setData(prev => ({
                  ...prev,
                  history: [addHistoryEntry('punishment', pun.title, pun.cost), ...prev.history],
                  stats: { ...prev.stats, totalCoins: Math.max(0, prev.stats.totalCoins - pun.cost) }
                }));
              }
            }}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={(id) => {}} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
