import React, { useState } from 'react';
import { Task } from '../types';

interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
  onReactivateTask: (id: string) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks, onReactivateTask }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);
  const [taskType, setTaskType] = useState<'recurring' | 'one-time'>('recurring');
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]); 
  const [reminderTime, setReminderTime] = useState('09:00');

  const daysOfWeek = [
    { id: 0, label: 'D' }, { id: 1, label: 'S' }, { id: 2, label: 'T' }, 
    { id: 3, label: 'Q' }, { id: 4, label: 'Q' }, { id: 5, label: 'S' }, { id: 6, label: 'S' }
  ];

  const addTask = () => {
    if (!newTitle.trim()) return;
    if (taskType === 'recurring' && selectedDays.length === 0) {
      alert("Selecione os dias para missões diárias!");
      return;
    }

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      type: taskType,
      recurringDays: taskType === 'recurring' ? selectedDays : [],
      reminderTime: reminderTime,
      completionCount: 0
    };
    onUpdateTasks([newTask, ...tasks]);
    setNewTitle('');
    setShowAdd(false);
  };

  const activeTasks = tasks.filter(t => !t.completed || t.type === 'recurring');
  const finishedOneTimeTasks = tasks.filter(t => t.type === 'one-time' && t.completed);

  return (
    <div className="p-6 pb-32">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Gerenciar Missões</h2>
        <button onClick={() => setShowAdd(true)} className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg">+</button>
      </div>

      {showAdd && (
        <div className="mb-6 bg-white p-5 rounded-2xl border border-blue-200 shadow-xl">
          <h3 className="font-bold text-slate-700 mb-4 text-sm">Nova Missão</h3>
          <div className="space-y-4">
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <button 
                onClick={() => setTaskType('recurring')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${taskType === 'recurring' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
              >
                Rotina
              </button>
              <button 
                onClick={() => setTaskType('one-time')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${taskType === 'one-time' ? 'bg-white text-purple-600 shadow-sm' : 'text-slate-400'}`}
              >
                Pontual
              </button>
            </div>
            <input 
              type="text" 
              placeholder="Título da missão..."
              className="w-full border-b-2 border-blue-100 p-2 focus:outline-none focus:border-blue-500 text-slate-700"
              value={newTitle}
              onChange={(e) => setNewTitle(e.target.value)}
            />
            {taskType === 'recurring' && (
              <div>
                <label className="text-[10px] font-black text-slate-400 block mb-2 uppercase">Dias da Semana:</label>
                <div className="flex justify-between">
                  {daysOfWeek.map(day => (
                    <button
                      key={day.id}
                      onClick={() => setSelectedDays(prev => prev.includes(day.id) ? prev.filter(d => d !== day.id) : [...prev, day.id])}
                      className={`w-8 h-8 rounded-full text-[10px] font-bold transition-all ${selectedDays.includes(day.id) ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                    >
                      {day.label}
                    </button>
                  ))}
                </div>
              </div>
            )}
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 block mb-1 uppercase">PTS Season</label>
                <input type="number" className="w-full bg-blue-50 p-2 rounded-lg text-xs font-bold" value={newXp} onChange={e => setNewXp(parseInt(e.target.value))} />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 block mb-1 uppercase">Moedas 🪙</label>
                <input type="number" className="w-full bg-green-50 p-2 rounded-lg text-xs font-bold" value={newCoins} onChange={e => setNewCoins(parseInt(e.target.value))} />
              </div>
            </div>
            <div className="flex gap-2 pt-2">
              <button onClick={() => setShowAdd(false)} className="flex-1 py-3 text-slate-400 font-bold text-xs uppercase">Sair</button>
              <button onClick={addTask} className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold text-xs uppercase shadow-md">Criar</button>
            </div>
          </div>
        </div>
      )}

      {/* Lista de Ativas */}
      <div className="space-y-6">
        <section>
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Em Aberto</h3>
            <div className="space-y-3">
                {activeTasks.map(task => (
                <div key={task.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
                    <div className="flex-1 min-w-0 pr-4">
                    <span className="block font-bold text-slate-700 truncate">{task.title}</span>
                    <div className="flex items-center gap-2 mt-1">
                        <span className={`text-[8px] px-1 rounded font-black uppercase ${task.type === 'one-time' ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'}`}>
                        {task.type === 'one-time' ? 'Pontual' : 'Rotina'}
                        </span>
                        <span className="text-[9px] text-slate-400 font-medium">{task.xp} pts | {task.coins} moedas</span>
                    </div>
                    </div>
                    <button onClick={() => onUpdateTasks(tasks.filter(t => t.id !== task.id))} className="text-red-200 hover:text-red-500 p-2">🗑️</button>
                </div>
                ))}
            </div>
        </section>

        {/* Lista de Concluídas (Somente Pontuais para Reiniciar) */}
        {finishedOneTimeTasks.length > 0 && (
            <section>
                <h3 className="text-xs font-black text-orange-400 uppercase tracking-widest mb-4">Concluídas (Reiniciar)</h3>
                <div className="space-y-3">
                    {finishedOneTimeTasks.map(task => (
                    <div key={task.id} className="bg-slate-50 p-4 rounded-2xl border border-dashed border-slate-200 flex items-center justify-between opacity-80">
                        <div className="flex-1 min-w-0">
                            <span className="block font-bold text-slate-400 line-through truncate">{task.title}</span>
                        </div>
                        <button 
                            onClick={() => onReactivateTask(task.id)}
                            className="bg-orange-100 text-orange-600 p-2 rounded-xl text-sm font-bold flex items-center gap-1 shadow-sm active:scale-95 transition-transform"
                            title="Reiniciar Missão"
                        >
                            <span>↺</span> <span className="text-[10px] uppercase">Reativar</span>
                        </button>
                    </div>
                    ))}
                </div>
            </section>
        )}
      </div>
    </div>
  );
};

export default TaskManager;

export interface Task {
  id: string;
  title: string;
  xp: number; // Agora convertido em Pontos de Temporada
  coins: number;
  completed: boolean;
  type: 'recurring' | 'one-time';
  recurringDays: number[];
  reminderTime?: string;   
  lastCompletedDate?: string; 
  completionCount: number; // Rastreio para bônus (7, 13, 21, 50, 100)
}

export interface Season {
  id: string;
  title: string;
  startDate: string;
  endDate: string;
  targetPoints: number;
  currentPoints: number;
  reward: string;
  isActive: boolean;
}

export interface Reward {
  id: string;
  title: string;
  cost: number;
  purchased: boolean;
  description: string;
}

export interface Punishment {
  id: string;
  title: string;
  cost: number;
  lastAppliedDate?: string; // Para controle de uma vez por dia
}

export interface HistoryEntry {
  id: string;
  type: 'task' | 'reward' | 'punishment' | 'bonus';
  title: string;
  value: number; // Pontos ou Moedas dependendo do contexto
  date: string; 
  relatedId?: string;
}

export interface UserStats {
  totalCoins: number;
}

export interface AppData {
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  history: HistoryEntry[];
  stats: UserStats;
  currentSeason: Season | null;
  dailyReviewTime: string; 
}

export type View = 'dashboard' | 'tasks' | 'shop' | 'punishments' | 'history' | 'settings';

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      // Reset de Tarefas e Punições Diárias
      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      parsed.punishments = (parsed.punishments || []).map((p: Punishment) => {
          // Se a data da última punição for diferente de hoje, liberamos para punir novamente
          return p;
      });

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost), ...prev.history],
      // Moedas podem ficar negativas agora
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    setData({ ...data, currentSeason: season });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);
    setData({ ...data, currentSeason: null });
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      {/* Alerta de Moedas Negativas */}
      {data.stats.totalCoins < 0 && (
          <div className="bg-red-600 text-white text-[10px] font-black uppercase py-1.5 px-4 text-center animate-pulse z-[60]">
              Saldo Negativo! Recupere suas moedas cumprindo missões.
          </div>
      )}

      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Temporada {new Date().getFullYear()}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3">
            <input 
              placeholder="Título da Season" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSName} onChange={e => setNewSName(e.target.value)}
            />
            <input 
              type="number" placeholder="Objetivo de Pontos" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value))}
            />
            <input 
              placeholder="Qual o prêmio final?" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSReward} onChange={e => setNewSReward(e.target.value)}
            />
            <button onClick={createSeason} className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${isGoalReached ? 'from-yellow-500 to-orange-600 ring-4 ring-yellow-200 ring-opacity-50' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada Ativa</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina do Dia
            </h2>
        </div>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma rotina cadastrada para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3 pb-8">

        {/* Missões Pontuais (Ocultas novamente) */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Sem tarefas pendentes.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Loja de Acessíveis */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Registro de Falhas (Uma vez por dia) */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      // Reset de Tarefas e Punições Diárias
      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      parsed.punishments = (parsed.punishments || []).map((p: Punishment) => {
          return p;
      });

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    setData({ ...data, currentSeason: season });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);
    setData({ ...data, currentSeason: null });
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Temporada {new Date().getFullYear()}</p>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3">
            <input 
              placeholder="Título da Season" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSName} onChange={e => setNewSName(e.target.value)}
            />
            <input 
              type="number" placeholder="Objetivo de Pontos" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value))}
            />
            <input 
              placeholder="Qual o prêmio final?" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSReward} onChange={e => setNewSReward(e.target.value)}
            />
            <button onClick={createSeason} className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${isGoalReached ? 'from-yellow-500 to-orange-600 ring-4 ring-yellow-200 ring-opacity-50' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada Ativa</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {/* Alerta de Saldo Negativo - Reposicionado */}
      {stats.totalCoins < 0 && (
        <div className="bg-red-500 text-white p-4 rounded-3xl text-[10px] font-black uppercase text-center animate-pulse shadow-lg border-2 border-red-400 flex items-center justify-center gap-2">
            <span className="text-lg">🚨</span>
            <span>Saldo Negativo: {stats.totalCoins} 🪙. Cumpra missões para recuperar!</span>
        </div>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina do Dia
            </h2>
        </div>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma rotina cadastrada para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3 pb-8">

        {/* Missões Pontuais */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Sem tarefas pendentes.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Loja de Acessíveis */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Registro de Falhas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

export interface Task {
  id: string;
  title: string;
  xp: number; // Agora convertido em Pontos de Temporada
  coins: number;
  completed: boolean;
  type: 'recurring' | 'one-time';
  recurringDays: number[];
  reminderTime?: string;   
  lastCompletedDate?: string; 
  completionCount: number; // Rastreio para bônus (7, 13, 21, 50, 100)
}

export interface Season {
  id: string;
  title: string;
  startDate: string;
  endDate: string;
  targetPoints: number;
  currentPoints: number;
  reward: string;
  isActive: boolean;
  seasonNumber: number; // Contador da temporada
}

export interface Reward {
  id: string;
  title: string;
  cost: number;
  purchased: boolean;
  description: string;
}

export interface Punishment {
  id: string;
  title: string;
  cost: number;
  lastAppliedDate?: string; // Para controle de uma vez por dia
}

export interface HistoryEntry {
  id: string;
  type: 'task' | 'reward' | 'punishment' | 'bonus' | 'season_end';
  title: string;
  value: number; // Pontos ou Moedas dependendo do contexto
  date: string; 
  relatedId?: string;
}

export interface UserStats {
  totalCoins: number;
}

export interface AppData {
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  history: HistoryEntry[];
  stats: UserStats;
  currentSeason: Season | null;
  dailyReviewTime: string; 
  seasonCount: number; // Contador global de temporadas
}

export type View = 'dashboard' | 'tasks' | 'shop' | 'punishments' | 'history' | 'settings';

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      if (parsed.seasonCount === undefined) parsed.seasonCount = 0;

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;

    // Registrar encerramento no histórico
    const statusText = isSuccess ? 'Sucesso 🏆' : 'Incompleta ❌';
    const historyTitle = `Fim da Temporada #${data.currentSeason.seasonNumber}: ${statusText}`;
    const endEntry = addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints);

    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);

    setData({ 
      ...data, 
      currentSeason: null,
      history: [endEntry, ...data.history]
    });
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward) return;
    const end = new Date();
    end.setMonth(end.getMonth() + 3);
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: end.toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true,
      seasonNumber: 0 // Será definido no App.tsx
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3">
            <input 
              placeholder="Título da Season" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSName} onChange={e => setNewSName(e.target.value)}
            />
            <input 
              type="number" placeholder="Objetivo de Pontos" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value))}
            />
            <input 
              placeholder="Qual o prêmio final?" 
              className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
              value={newSReward} onChange={e => setNewSReward(e.target.value)}
            />
            <button onClick={createSeason} className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${isGoalReached ? 'from-yellow-500 to-orange-600 ring-4 ring-yellow-200 ring-opacity-50' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {/* Alerta de Saldo Negativo */}
      {stats.totalCoins < 0 && (
        <div className="bg-red-500 text-white p-4 rounded-3xl text-[10px] font-black uppercase text-center animate-pulse shadow-lg border-2 border-red-400 flex items-center justify-center gap-2">
            <span className="text-lg">🚨</span>
            <span>Saldo Negativo: {stats.totalCoins} 🪙. Cumpra missões para recuperar!</span>
        </div>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina do Dia
            </h2>
        </div>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma rotina cadastrada para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3 pb-8">

        {/* Missões Pontuais */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Sem tarefas pendentes.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Loja de Acessíveis */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Registro de Falhas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { HistoryEntry } from '../types';

interface HistoryManagerProps {
  history: HistoryEntry[];
  onDeleteEntry: (id: string) => void;
}

const HistoryManager: React.FC<HistoryManagerProps> = ({ history, onDeleteEntry }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Navegação do Calendário
  const prevMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));

  // Geração de dias do mês
  const getDaysInMonth = (year: number, month: number) => {
    const date = new Date(year, month, 1);
    const days = [];
    while (date.getMonth() === month) {
      days.push(new Date(date));
      date.setDate(date.getDate() + 1);
    }
    return days;
  };

  const monthDays = getDaysInMonth(currentDate.getFullYear(), currentDate.getMonth());
  const firstDayOfMonth = monthDays[0].getDay();
  const emptyDays = Array(firstDayOfMonth).fill(null);

  // Filtragem de histórico por data
  const getEntriesForDate = (dateStr: string) => {
    return history.filter(e => e.date.split('T')[0] === dateStr);
  };

  const hasActivity = (dateStr: string) => {
    return history.some(e => e.date.split('T')[0] === dateStr);
  };

  const dayEntries = getEntriesForDate(selectedDate);

  const getEntryStyles = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'task': return { icon: '✅', color: 'text-blue-600', bg: 'bg-blue-50', label: 'Ganho' };
      case 'reward': return { icon: '🎁', color: 'text-green-600', bg: 'bg-green-50', label: 'Resgate' };
      case 'punishment': return { icon: '⚠️', color: 'text-red-600', bg: 'bg-red-50', label: 'Falha' };
      case 'bonus': return { icon: '🔥', color: 'text-yellow-600', bg: 'bg-yellow-50', label: 'Bônus' };
      case 'season_end': return { icon: '🏆', color: 'text-indigo-600', bg: 'bg-indigo-50', label: 'Temporada' };
    }
  };

  const monthName = currentDate.toLocaleString('pt-BR', { month: 'long', year: 'numeric' });

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold text-slate-800 mb-6">Sua Jornada</h2>

      {/* Calendário */}
      <div className="bg-white rounded-3xl border border-blue-100 shadow-sm overflow-hidden mb-6">
        <div className="flex justify-between items-center bg-blue-50/50 p-4 border-b border-blue-100">
          <button onClick={prevMonth} className="p-2 text-blue-600 hover:bg-blue-100 rounded-full transition-colors">◀</button>
          <span className="font-bold text-blue-800 uppercase text-xs tracking-wider">{monthName}</span>
          <button onClick={nextMonth} className="p-2 text-blue-600 hover:bg-blue-100 rounded-full transition-colors">▶</button>
        </div>

        <div className="grid grid-cols-7 text-center p-2">
          {['D', 'S', 'T', 'Q', 'Q', 'S', 'S'].map(d => (
            <div key={d} className="text-[10px] font-black text-slate-300 py-2 uppercase">{d}</div>
          ))}

          {emptyDays.map((_, i) => <div key={`empty-${i}`} className="p-2" />)}

          {monthDays.map(day => {
            const dateStr = day.toISOString().split('T')[0];
            const isSelected = selectedDate === dateStr;
            const active = hasActivity(dateStr);
            const isToday = new Date().toISOString().split('T')[0] === dateStr;

            return (
              <button
                key={dateStr}
                onClick={() => setSelectedDate(dateStr)}
                className={`relative flex flex-col items-center justify-center aspect-square rounded-xl text-sm transition-all ${
                  isSelected 
                  ? 'bg-blue-600 text-white font-bold shadow-lg scale-110 z-10' 
                  : isToday 
                    ? 'bg-blue-50 text-blue-600 font-bold border border-blue-200' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                {day.getDate()}
                {active && !isSelected && (
                  <span className="absolute bottom-1 w-1 h-1 bg-blue-400 rounded-full" />
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Detalhes do Dia */}
      <div className="space-y-4 pb-32">
        <div className="flex justify-between items-end">
          <h3 className="text-sm font-bold text-slate-500 uppercase tracking-tight">Atividades do dia</h3>
          <span className="text-[10px] font-bold text-slate-300">{selectedDate.split('-').reverse().join('/')}</span>
        </div>

        {dayEntries.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-3xl border border-dashed border-slate-200">
            <span className="text-4xl block mb-2 opacity-20">📭</span>
            <p className="text-xs text-slate-300">Nenhum registro nesta data.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {dayEntries.map(entry => {
              const s = getEntryStyles(entry.type);
              return (
                <div key={entry.id} className={`p-4 rounded-2xl border shadow-sm flex items-center gap-4 transition-all ${entry.type === 'season_end' ? 'bg-indigo-50 border-indigo-100' : 'bg-white border-slate-100'}`}>
                  <div className={`w-10 h-10 ${s.bg} rounded-full flex items-center justify-center text-lg shadow-inner`}>{s.icon}</div>
                  <div className="flex-1 min-w-0">
                    <span className={`block font-bold truncate text-sm ${entry.type === 'season_end' ? 'text-indigo-800' : 'text-slate-700'}`}>{entry.title}</span>
                    <span className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{s.label}</span>
                  </div>
                  <div className="text-right flex items-center gap-3">
                    <span className={`font-black text-sm ${s.color}`}>
                      {entry.type === 'task' || entry.type === 'bonus' || entry.type === 'season_end' ? '+' : '-'}{entry.value}
                    </span>
                    <button 
                        onClick={() => onDeleteEntry(entry.id)} 
                        className="w-8 h-8 flex items-center justify-center bg-red-50 text-red-300 hover:text-red-500 rounded-full transition-colors active:scale-90"
                    >
                        ✕
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryManager;

const CACHE_NAME = 'gamiroutine-v1';
const ASSETS = [
  '/',
  '/index.html',
  '/manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

