import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const defaultDate = new Date();
    defaultDate.setMonth(defaultDate.getMonth() + 1);
    return defaultDate.toISOString().split('T')[0];
  });

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const createSeason = () => {
    if (!newSName || !newSReward || !newSEndDate) {
      alert("Preencha todos os campos da temporada!");
      return;
    }

    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: new Date(newSEndDate + 'T23:59:59').toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true,
      seasonNumber: 0 // Será definido no App.tsx
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3 text-left">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título</label>
              <input 
                placeholder="Ex: Foco Total, Verão 2024..." 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSName} onChange={e => setNewSName(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta de Pontos</label>
                <input 
                  type="number" placeholder="5000" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input 
                  type="date" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)}
                />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Prêmio Final</label>
              <input 
                placeholder="O que você ganhará ao vencer?" 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSReward} onChange={e => setNewSReward(e.target.value)}
              />
            </div>
            <button onClick={createSeason} className="w-full py-3 mt-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${isGoalReached ? 'from-yellow-500 to-orange-600 ring-4 ring-yellow-200 ring-opacity-50' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
              <p className="text-[9px] opacity-60 font-bold uppercase tracking-tight">Até {new Date(season.endDate).toLocaleDateString('pt-BR')}</p>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {/* Alerta de Saldo Negativo */}
      {stats.totalCoins < 0 && (
        <div className="bg-red-500 text-white p-4 rounded-3xl text-[10px] font-black uppercase text-center animate-pulse shadow-lg border-2 border-red-400 flex items-center justify-center gap-2">
            <span className="text-lg">🚨</span>
            <span>Saldo Negativo: {stats.totalCoins} 🪙. Cumpra missões para recuperar!</span>
        </div>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina do Dia
            </h2>
        </div>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma rotina cadastrada para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3 pb-8">

        {/* Missões Pontuais */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Sem tarefas pendentes.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Loja de Acessíveis */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Registro de Falhas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      if (parsed.seasonCount === undefined) parsed.seasonCount = 0;

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;

    // Registrar encerramento no histórico
    const statusText = isSuccess ? 'Sucesso 🏆' : 'Incompleta ❌';
    const historyTitle = `Fim da Temporada #${data.currentSeason.seasonNumber}: ${statusText}`;
    const endEntry = addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints);

    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);

    setData({ 
      ...data, 
      currentSeason: null,
      history: [endEntry, ...data.history]
    });
  };

  const handleReset = () => {
    if (confirm('TEM CERTEZA? Isso apagará TODAS as tarefas, recompensas, histórico e reiniciará a contagem de temporadas.')) {
      localStorage.removeItem('gami_routine_data');
      setData(INITIAL_DATA);
      setCurrentView('dashboard');
    }
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} onReset={handleReset} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const defaultDate = new Date();
    defaultDate.setMonth(defaultDate.getMonth() + 1);
    return defaultDate.toISOString().split('T')[0];
  });

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  // Filtros de Tarefas
  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);

  // Filtro de Loja: Apenas o que posso comprar
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  // Lógica de Cores Dinâmicas
  const getSeasonCardTheme = () => {
    if (!season) return 'from-indigo-600 to-blue-700';

    const today = new Date();
    const end = new Date(season.endDate);
    const diffTime = end.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    const pointsMissing = season.targetPoints - season.currentPoints;
    const percentMissing = (pointsMissing / season.targetPoints) * 100;

    // Se já atingiu a meta
    if (isGoalReached) {
        if (diffDays <= 10) return 'from-emerald-600 to-green-700'; // Verde se atingiu e está no fim
        return 'from-yellow-500 to-orange-600'; // Dourado padrão
    }

    // Se faltar 10 dias ou menos
    if (diffDays <= 10) {
        if (percentMissing > 10) {
            return 'from-red-600 to-rose-700'; // Vermelho: falta muito
        } else {
            return 'from-amber-500 to-yellow-600'; // Amarelo: falta pouco
        }
    }

    return 'from-indigo-600 to-blue-700'; // Azul padrão
  };

  const getRemainingDaysText = () => {
    if (!season) return "";
    const today = new Date();
    const end = new Date(season.endDate);
    const diffTime = end.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return "Encerrada";
    if (diffDays === 0) return "Termina hoje!";
    if (diffDays === 1) return "Falta 1 dia";
    return `Faltam ${diffDays} dias`;
  };

  const createSeason = () => {
    if (!newSName || !newSReward || !newSEndDate) {
      alert("Preencha todos os campos da temporada!");
      return;
    }

    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: new Date(newSEndDate + 'T23:59:59').toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true,
      seasonNumber: 0 // Será definido no App.tsx
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {/* Efeito de Festa se a meta for atingida */}
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {/* Season Card */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3 text-left">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título</label>
              <input 
                placeholder="Ex: Foco Total, Verão 2024..." 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSName} onChange={e => setNewSName(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta de Pontos</label>
                <input 
                  type="number" placeholder="5000" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input 
                  type="date" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)}
                />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Prêmio Final</label>
              <input 
                placeholder="O que você ganhará ao vencer?" 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSReward} onChange={e => setNewSReward(e.target.value)}
              />
            </div>
            <button onClick={createSeason} className="w-full py-3 mt-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${getSeasonCardTheme()}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-[9px] bg-black/20 px-2 py-0.5 rounded-full font-bold uppercase tracking-tight">Até {new Date(season.endDate).toLocaleDateString('pt-BR')}</span>
                <span className="text-[9px] font-black uppercase bg-white/20 px-2 py-0.5 rounded-full">{getRemainingDaysText()}</span>
              </div>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {/* Alerta de Saldo Negativo */}
      {stats.totalCoins < 0 && (
        <div className="bg-red-500 text-white p-4 rounded-3xl text-[10px] font-black uppercase text-center animate-pulse shadow-lg border-2 border-red-400 flex items-center justify-center gap-2">
            <span className="text-lg">🚨</span>
            <span>Saldo Negativo: {stats.totalCoins} 🪙. Cumpra missões para recuperar!</span>
        </div>
      )}

      {/* Missões de Rotina */}
      <section>
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span>📅</span> Rotina do Dia
            </h2>
        </div>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma rotina cadastrada para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black">🔥 {task.completionCount || 0}x</span>
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions Ocultos */}
      <div className="space-y-3 pb-8">

        {/* Missões Pontuais */}
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
                <span className={`transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2">Sem tarefas pendentes.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <span className="text-xs font-bold text-slate-700">{task.title}</span>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1 rounded-lg text-[10px] font-bold">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Loja de Acessíveis */}
        <section className="bg-white rounded-2xl border border-green-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsShopOpen(!isShopOpen)} className="w-full p-4 flex justify-between items-center bg-green-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        {/* Registro de Falhas */}
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { AppData } from '../types';

interface SettingsProps {
  data: AppData;
  onImport: (data: AppData) => void;
  onUpdateTime: (time: string) => void;
  onReset: () => void;
}

const Settings: React.FC<SettingsProps> = ({ data, onImport, onUpdateTime, onReset }) => {
  const exportBackup = () => {
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `gami_routine_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importBackup = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const importedData = JSON.parse(e.target?.result as string);
        if (importedData.stats && importedData.tasks) {
          onImport(importedData);
          alert('Backup importado com sucesso!');
        } else {
          throw new Error('Formato inválido');
        }
      } catch (err) {
        alert('Erro ao importar backup. Verifique o arquivo JSON.');
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="p-6 pb-32">
      <h2 className="text-2xl font-bold text-slate-800 mb-6">Configurações</h2>

      <div className="space-y-6">
        <section className="bg-white p-6 rounded-3xl border border-blue-50 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
            <span>⏰</span> Lembrete de Revisão
          </h3>
          <p className="text-sm text-slate-500 mb-4 leading-relaxed">
            Horário para receber um alerta geral e revisar as tarefas do dia:
          </p>
          <input 
            type="time" 
            className="w-full bg-slate-50 p-4 rounded-2xl border border-slate-100 text-slate-600 font-bold text-xl"
            value={data.dailyReviewTime}
            onChange={(e) => onUpdateTime(e.target.value)}
          />
        </section>

        <section className="bg-white p-6 rounded-3xl border border-blue-50 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2">
            <span>💾</span> Dados e Backup
          </h3>
          <div className="space-y-3">
            <button onClick={exportBackup} className="w-full py-4 bg-blue-50 text-blue-600 rounded-2xl font-bold text-sm uppercase tracking-wide border border-blue-100 flex items-center justify-center gap-2 hover:bg-blue-100 transition-colors">
              <span>📤</span> Exportar Backup
            </button>
            <div className="relative">
              <input type="file" accept=".json" onChange={importBackup} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
              <button className="w-full py-4 bg-green-50 text-green-600 rounded-2xl font-bold text-sm uppercase tracking-wide border border-green-100 flex items-center justify-center gap-2 pointer-events-none">
                <span>📥</span> Importar Backup
              </button>
            </div>
          </div>
        </section>

        <section className="bg-white p-6 rounded-3xl border border-red-50 shadow-sm">
          <h3 className="font-bold text-red-700 mb-4 flex items-center gap-2">
            <span>⚠️</span> Zona de Perigo
          </h3>
          <p className="text-xs text-slate-400 mb-4">Atenção: Esta ação é irreversível e apagará todo o seu progresso.</p>
          <button 
            onClick={onReset}
            className="w-full py-4 bg-red-50 text-red-600 rounded-2xl font-bold text-sm uppercase tracking-wide border border-red-100 flex items-center justify-center gap-2 hover:bg-red-100 transition-colors"
          >
            <span>🗑️</span> Resetar Aplicação
          </button>
        </section>

        <section className="p-4 bg-blue-600 rounded-3xl text-white">
            <h4 className="font-bold mb-2">Instruções Mobile</h4>
            <ol className="text-xs space-y-2 opacity-90 list-decimal pl-4">
                <li>Abra no Safari (iOS) ou Chrome (Android).</li>
                <li>Toque em "Adicionar à Tela de Início".</li>
                <li>Ele funcionará offline como um app nativo.</li>
            </ol>
        </section>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      if (parsed.seasonCount === undefined) parsed.seasonCount = 0;

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;

    const statusText = isSuccess ? 'Sucesso 🏆' : 'Incompleta ❌';
    const historyTitle = `Fim da Temporada #${data.currentSeason.seasonNumber}: ${statusText}`;
    const endEntry = addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints);

    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);

    setData({ 
      ...data, 
      currentSeason: null,
      history: [endEntry, ...data.history]
    });
  };

  const handleReset = () => {
    const confirmed = confirm('TEM CERTEZA ABSOLUTA? Isso apagará TODAS as tarefas, recompensas, histórico e reiniciará a contagem de temporadas.');
    if (confirmed) {
      localStorage.removeItem('gami_routine_data');
      setData({ ...INITIAL_DATA });
      setCurrentView('dashboard');
    }
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div>
          <h1 className="text-xl font-bold text-blue-600">GamiRoutine</h1>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} onReset={handleReset} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const defaultDate = new Date();
    defaultDate.setMonth(defaultDate.getMonth() + 1);
    return defaultDate.toISOString().split('T')[0];
  });

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDay = new Date().getDay();

  const routineTasks = tasks.filter(t => t.type === 'recurring' && t.recurringDays.includes(currentDay));
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isSeasonExpired = season ? new Date() > new Date(season.endDate) : false;

  const getSeasonCardTheme = () => {
    if (!season) return 'from-indigo-600 to-blue-700';

    const today = new Date();
    const end = new Date(season.endDate);
    const diffTime = end.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    const progressPercent = (season.currentPoints / season.targetPoints) * 100;

    // Lógica quando faltam 10 dias ou menos
    if (diffDays <= 10) {
        if (isGoalReached) {
            return 'from-emerald-600 to-green-700'; // Verde se atingido
        } else if (progressPercent < 90) {
            return 'from-red-600 to-rose-700'; // Vermelho se faltar mais de 10%
        } else {
            return 'from-amber-500 to-yellow-600'; // Amarelo se faltar menos de 10%
        }
    }

    // Padrão
    if (isGoalReached) return 'from-yellow-500 to-orange-600';
    return 'from-indigo-600 to-blue-700';
  };

  const getRemainingDaysText = () => {
    if (!season) return "";
    const today = new Date();
    const end = new Date(season.endDate);
    const diffTime = end.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return "Encerrada";
    if (diffDays === 0) return "Termina hoje!";
    if (diffDays === 1) return "Último dia!";
    return `Faltam ${diffDays} dias`;
  };

  const createSeason = () => {
    if (!newSName || !newSReward || !newSEndDate) {
      alert("Preencha todos os campos da temporada!");
      return;
    }

    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: new Date(newSEndDate + 'T23:59:59').toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true,
      seasonNumber: 0
    };
    onCreateSeason(newSeason);
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      {isGoalReached && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0">
          <div className="confetti-container">
            {[...Array(20)].map((_, i) => (
              <div key={i} className={`confetti piece-${i % 5}`} style={{ left: `${Math.random() * 100}%`, animationDelay: `${Math.random() * 3}s` }} />
            ))}
          </div>
        </div>
      )}

      <style>{`
        .confetti {
          position: absolute;
          width: 8px;
          height: 8px;
          background: #ffd700;
          top: -10px;
          opacity: 0;
          animation: drop 3s infinite linear;
        }
        .piece-0 { background: #ff6b6b; }
        .piece-1 { background: #4ecdc4; }
        .piece-2 { background: #ffe66d; }
        .piece-3 { background: #1a535c; }
        .piece-4 { background: #f7fff7; }
        @keyframes drop {
          0% { top: -10px; opacity: 1; transform: rotate(0deg); }
          100% { top: 100%; opacity: 0; transform: rotate(360deg); }
        }
      `}</style>

      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 text-center">
          <span className="text-4xl block mb-2">🗓️</span>
          <h3 className="font-bold text-slate-800 mb-4">Nova Temporada</h3>
          <div className="space-y-3 text-left">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título</label>
              <input 
                placeholder="Ex: Foco Total, Verão 2024..." 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSName} onChange={e => setNewSName(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta de Pontos</label>
                <input 
                  type="number" placeholder="5000" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input 
                  type="date" 
                  className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400 font-bold"
                  value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)}
                />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Prêmio Final</label>
              <input 
                placeholder="O que você ganhará ao vencer?" 
                className="w-full bg-slate-50 p-3 rounded-xl border border-slate-100 text-sm focus:outline-none focus:border-blue-400"
                value={newSReward} onChange={e => setNewSReward(e.target.value)}
              />
            </div>
            <button onClick={createSeason} className="w-full py-3 mt-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg active:scale-95 transition-transform">Iniciar Season</button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${getSeasonCardTheme()}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-[10px] bg-black/20 px-2 py-0.5 rounded-full font-black uppercase tracking-tight">Até {new Date(season.endDate).toLocaleDateString('pt-BR')}</span>
                <span className="text-[10px] font-black uppercase bg-white/20 px-2 py-0.5 rounded-full shadow-sm">{getRemainingDaysText()}</span>
              </div>
            </div>
            {(isSeasonExpired || isGoalReached) && (
              <div className="flex flex-col gap-2 items-end">
                {isGoalReached && (
                    <span className="bg-white text-orange-600 px-2 py-0.5 rounded-full text-[8px] font-black uppercase shadow-sm">Meta Atingida! 🏆</span>
                )}
                <button 
                  onClick={onEndSeason}
                  className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase"
                >
                  Concluir Season
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} 
                style={{ width: `${getSeasonProgress()}%` }} 
              />
            </div>
          </div>

          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce cursor-pointer hover:bg-white/30 transition-all" onClick={() => alert(`🎉 PARABÉNS! Você conquistou: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase text-center mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black text-center">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      {stats.totalCoins < 0 && (
        <div className="bg-red-500 text-white p-4 rounded-3xl text-[10px] font-black uppercase text-center animate-pulse shadow-lg border-2 border-red-400 flex items-center justify-center gap-2">
            <span className="text-lg">🚨</span>
