        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
            </div>
            <div className="flex items-center gap-2">
                {oneTimeTasks.length > 0 && <span className="bg-purple-200 text-purple-700 text-[10px] px-2 py-0.5 rounded-full font-black">{oneTimeTasks.length}</span>}
