            <div className="flex items-center gap-2">
              <span className="text-lg">🛍️</span>
              <span className="font-bold text-green-800 text-sm">Resgates Disponíveis</span>
            </div>
            <div className="flex items-center gap-2">
                {affordableRewards.length > 0 && <span className="bg-green-500 text-white text-[10px] px-2 py-0.5 rounded-full font-black">{affordableRewards.length}</span>}
                <span className={`transform transition-transform ${isShopOpen ? 'rotate-180' : ''}`}>▼</span>
            </div>
          </button>
          {isShopOpen && (
            <div className="p-4 space-y-3 border-t border-green-100">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-4">Saldo insuficiente para resgates.</p>
              ) : (
                affordableRewards.map(r => (
                  <div key={r.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                    <div>
                        <span className="block text-xs font-bold text-slate-700">{r.title}</span>
                        <span className="text-[10px] text-green-600 font-bold">{r.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(r.id)} className="bg-green-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </section>

        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas (Diário)</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.length === 0 ? <p className="text-[10px] text-slate-400 text-center py-2">Sem punições.</p> : punishments.map(p => {
                const isAppliedToday = p.lastAppliedDate === todayStr;
                return (
                  <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border ${isAppliedToday ? 'bg-slate-50 border-slate-100 opacity-50' : 'bg-orange-50/50 border-orange-100'}`}>
                    <div className="flex-1">
                        <span className={`block text-xs font-bold ${isAppliedToday ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{p.title}</span>
                        <span className="text-[10px] text-orange-600 font-black">-{p.cost} 🪙</span>
                    </div>
                    {!isAppliedToday ? (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                    ) : (
                        <span className="text-orange-500 font-bold px-2 text-xs">Registrada</span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

