// Ícone do app baseado na imagem fornecida (Representado por Base64 para fins de demonstração no ambiente web)
const APP_ICON = "https://i.ibb.co/C386YvW/patrick-pixel.png"; // Usando URL estável da imagem ou base64

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        if (t.completionCount === undefined) t.completionCount = 0;
        return t;
      });

      if (parsed.seasonCount === undefined) parsed.seasonCount = 0;

      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    const entry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    };
    return entry;
  };

  const checkMilestoneBonus = (count: number) => {
    const milestones = { 7: 100, 13: 200, 21: 500, 50: 1000, 100: 2500 };
    return milestones[count as keyof typeof milestones] || 0;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;
    const bonusPoints = checkMilestoneBonus(newCompletionCount);

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    const newHistory = [addHistoryEntry('task', task.title, task.xp, task.id)];
    if (bonusPoints > 0) {
      newHistory.push(addHistoryEntry('bonus', `Bônus ${newCompletionCount}x: ${task.title}`, bonusPoints));
    }

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [...newHistory, ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp + bonusPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false } : t)
    }));
  };

  const handlePurchaseReward = (id: string) => {
    const reward = data.rewards.find(r => r.id === id);
    if (!reward || data.stats.totalCoins < reward.cost) return;

    const bonusSeasonPoints = 10;

    setData(prev => ({
      ...prev,
      history: [addHistoryEntry('reward', reward.title, reward.cost), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + bonusSeasonPoints
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - reward.cost }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun || pun.lastAppliedDate === today) return;

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    const entry = data.history.find(e => e.id === entryId);
    if (!entry) return;
    if (!confirm('Deseja excluir e estornar?')) return;

    let newCoins = data.stats.totalCoins;
    let newSeasonPoints = data.currentSeason?.currentPoints || 0;
    let newTasks = [...data.tasks];
    let newPunishments = [...data.punishments];

    if (entry.type === 'task') {
      newSeasonPoints -= entry.value;
      const task = newTasks.find(t => t.id === entry.relatedId);
      if (task) {
        newCoins -= task.coins;
        newTasks = newTasks.map(t => t.id === entry.relatedId ? { ...t, completed: false, completionCount: Math.max(0, t.completionCount - 1) } : t);
      }
    } else if (entry.type === 'punishment') {
        newCoins += entry.value;
        newPunishments = newPunishments.map(p => p.id === entry.relatedId ? { ...p, lastAppliedDate: undefined } : p);
    } else if (entry.type === 'bonus' || entry.type === 'reward') {
      if (entry.type === 'bonus') newSeasonPoints -= entry.value;
      else if (entry.type === 'reward') {
          newCoins += entry.value;
          newSeasonPoints -= 10;
      }
    }

    setData(prev => ({
      ...prev,
      history: prev.history.filter(e => e.id !== entryId),
      tasks: newTasks,
      punishments: newPunishments,
      currentSeason: prev.currentSeason ? { ...prev.currentSeason, currentPoints: Math.max(0, newSeasonPoints) } : null,
      stats: { ...prev.stats, totalCoins: newCoins }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;

    const statusText = isSuccess ? 'Sucesso 🏆' : 'Incompleta ❌';
    const historyTitle = `Fim da Temporada #${data.currentSeason.seasonNumber}: ${statusText}`;
    const endEntry = addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints);

    alert(`Temporada "${data.currentSeason.title}" finalizada!\n${isSuccess ? '🏆 OBJETIVO ALCANÇADO!' : '❌ Meta não atingida.'}\nResumo: ${data.currentSeason.currentPoints} pontos acumulados.`);

    setData({ 
      ...data, 
      currentSeason: null,
      history: [endEntry, ...data.history]
    });
  };

  const handleReset = () => {
    const confirmed = confirm('TEM CERTEZA ABSOLUTA? Isso apagará TODAS as tarefas, recompensas, histórico e reiniciará a contagem de temporadas.');
    if (confirmed) {
      localStorage.removeItem('gami_routine_data');
      setData({ ...INITIAL_DATA });
      setCurrentView('dashboard');
    }
  };

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div className="flex items-center gap-3">
          <img 
            src={APP_ICON} 
            className="w-12 h-12 rounded-full border-2 border-blue-100 shadow-md object-cover" 
            alt="App Logo" 
          />
          <div>
            <h1 className="text-xl font-bold text-blue-600">Patrick's Life</h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-colors ${data.stats.totalCoins < 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-bold ${data.stats.totalCoins < 0 ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} 
            tasks={data.tasks} 
            rewards={data.rewards} 
            punishments={data.punishments} 
            season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={handlePurchaseReward}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && (
          <TaskManager 
            tasks={data.tasks} 
            onUpdateTasks={(tasks) => setData({...data, tasks})} 
            onReactivateTask={handleReactivateTask}
          />
        )}
        {currentView === 'shop' && (
          <RewardShop 
            rewards={data.rewards} 
            coins={data.stats.totalCoins} 
            onUpdateRewards={(rewards) => setData({...data, rewards})} 
            onPurchase={handlePurchaseReward} 
          />
        )}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} onReset={handleReset} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { HistoryEntry } from '../types';

interface HistoryManagerProps {
  history: HistoryEntry[];
  onDeleteEntry: (id: string) => void;
}

const HistoryManager: React.FC<HistoryManagerProps> = ({ history, onDeleteEntry }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [filterType, setFilterType] = useState<HistoryEntry['type'] | 'all'>('all');

  // Navegação do Calendário
  const prevMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));

  // Geração de dias do mês
  const getDaysInMonth = (year: number, month: number) => {
    const date = new Date(year, month, 1);
    const days = [];
    while (date.getMonth() === month) {
      days.push(new Date(date));
      date.setDate(date.getDate() + 1);
    }
    return days;
  };

  const monthDays = getDaysInMonth(currentDate.getFullYear(), currentDate.getMonth());
  const firstDayOfMonth = monthDays[0].getDay();
  const emptyDays = Array(firstDayOfMonth).fill(null);

  // Filtragem de histórico por data e tipo
  const getEntriesForDate = (dateStr: string) => {
    let filtered = history.filter(e => e.date.split('T')[0] === dateStr);
    if (filterType !== 'all') {
      filtered = filtered.filter(e => e.type === filterType);
    }
    return filtered;
  };

  const hasActivity = (dateStr: string) => {
    return history.some(e => e.date.split('T')[0] === dateStr);
  };

  const dayEntries = getEntriesForDate(selectedDate);

  const getEntryStyles = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'task': return { icon: '✅', color: 'text-blue-600', bg: 'bg-blue-50', label: 'Ganho' };
      case 'reward': return { icon: '🎁', color: 'text-green-600', bg: 'bg-green-50', label: 'Resgate' };
      case 'punishment': return { icon: '⚠️', color: 'text-red-600', bg: 'bg-red-50', label: 'Falha' };
      case 'bonus': return { icon: '🔥', color: 'text-yellow-600', bg: 'bg-yellow-50', label: 'Bônus' };
      case 'season_end': return { icon: '🏆', color: 'text-indigo-600', bg: 'bg-indigo-50', label: 'Temporada' };
    }
  };

  const monthName = currentDate.toLocaleString('pt-BR', { month: 'long', year: 'numeric' });

  const filterOptions: { id: HistoryEntry['type'] | 'all', label: string, icon: string }[] = [
    { id: 'all', label: 'Tudo', icon: '🌐' },
    { id: 'task', label: 'Missões', icon: '✅' },
    { id: 'reward', label: 'Resgates', icon: '🎁' },
    { id: 'punishment', label: 'Falhas', icon: '⚠️' },
    { id: 'bonus', label: 'Bônus', icon: '🔥' },
    { id: 'season_end', label: 'Season', icon: '🏆' },
  ];

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold text-slate-800 mb-6">Sua Jornada</h2>

      {/* Calendário */}
      <div className="bg-white rounded-3xl border border-blue-100 shadow-sm overflow-hidden mb-6">
        <div className="flex justify-between items-center bg-blue-50/50 p-4 border-b border-blue-100">
          <button onClick={prevMonth} className="p-2 text-blue-600 hover:bg-blue-100 rounded-full transition-colors">◀</button>
          <span className="font-bold text-blue-800 uppercase text-xs tracking-wider">{monthName}</span>
          <button onClick={nextMonth} className="p-2 text-blue-600 hover:bg-blue-100 rounded-full transition-colors">▶</button>
        </div>

        <div className="grid grid-cols-7 text-center p-2">
          {['D', 'S', 'T', 'Q', 'Q', 'S', 'S'].map(d => (
            <div key={d} className="text-[10px] font-black text-slate-300 py-2 uppercase">{d}</div>
          ))}

          {emptyDays.map((_, i) => <div key={`empty-${i}`} className="p-2" />)}

          {monthDays.map(day => {
            const dateStr = day.toISOString().split('T')[0];
            const isSelected = selectedDate === dateStr;
            const active = hasActivity(dateStr);
            const isToday = new Date().toISOString().split('T')[0] === dateStr;

            return (
              <button
                key={dateStr}
                onClick={() => setSelectedDate(dateStr)}
                className={`relative flex flex-col items-center justify-center aspect-square rounded-xl text-sm transition-all ${
                  isSelected 
                  ? 'bg-blue-600 text-white font-bold shadow-lg scale-110 z-10' 
                  : isToday 
                    ? 'bg-blue-50 text-blue-600 font-bold border border-blue-200' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                {day.getDate()}
                {active && !isSelected && (
                  <span className="absolute bottom-1 w-1 h-1 bg-blue-400 rounded-full" />
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Filtros */}
      <div className="mb-6 flex gap-2 overflow-x-auto pb-2 no-scrollbar">
        {filterOptions.map(opt => (
          <button
            key={opt.id}
            onClick={() => setFilterType(opt.id)}
            className={`px-4 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all border ${
              filterType === opt.id 
              ? 'bg-blue-600 text-white border-blue-600 shadow-md' 
              : 'bg-white text-slate-400 border-slate-100'
            }`}
          >
            {opt.icon} {opt.label}
          </button>
        ))}
      </div>

      {/* Detalhes do Dia */}
      <div className="space-y-4 pb-32">
        <div className="flex justify-between items-end">
          <h3 className="text-sm font-bold text-slate-500 uppercase tracking-tight">Atividades do dia</h3>
          <span className="text-[10px] font-bold text-slate-300">{selectedDate.split('-').reverse().join('/')}</span>
        </div>

        {dayEntries.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-3xl border border-dashed border-slate-200">
            <span className="text-4xl block mb-2 opacity-20">📭</span>
            <p className="text-xs text-slate-300">Nenhum registro encontrado.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {dayEntries.map(entry => {
              const s = getEntryStyles(entry.type);
              return (
                <div key={entry.id} className={`p-4 rounded-2xl border shadow-sm flex items-center gap-4 transition-all ${entry.type === 'season_end' ? 'bg-indigo-50 border-indigo-100' : 'bg-white border-slate-100'}`}>
                  <div className={`w-10 h-10 ${s.bg} rounded-full flex items-center justify-center text-lg shadow-inner`}>{s.icon}</div>
                  <div className="flex-1 min-w-0">
                    <span className={`block font-bold truncate text-sm ${entry.type === 'season_end' ? 'text-indigo-800' : 'text-slate-700'}`}>{entry.title}</span>
                    <span className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{s.label}</span>
                  </div>
                  <div className="text-right flex items-center gap-3">
                    <span className={`font-black text-sm ${s.color}`}>
                      {entry.type === 'task' || entry.type === 'bonus' || entry.type === 'season_end' ? '+' : '-'}{entry.value}
                    </span>
                    <button 
                        onClick={() => onDeleteEntry(entry.id)} 
                        className="w-8 h-8 flex items-center justify-center bg-red-50 text-red-300 hover:text-red-500 rounded-full transition-colors active:scale-90"
                    >
                        ✕
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

