export type View = 'dashboard' | 'tasks' | 'shop' | 'punishments' | 'history' | 'settings';

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentDayOfWeek = today.getDay();
  const currentDateNum = today.getDate();

  const isTaskDueToday = (task: Task) => {
    if (task.completed && task.lastCompletedDate === todayStr) return true; // Mostrar se já completou hoje

    if (task.type === 'one-time') return !task.completed;

    if (task.recurringType === 'monthly' && task.monthlyPattern) {
      const { week, day } = task.monthlyPattern;
      if (currentDayOfWeek !== day) return false;

      if (week <= 4) {
        // Verifica se é a N-ésima ocorrência do dia
        const firstDayOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);
        let count = 0;
        for (let d = 1; d <= currentDateNum; d++) {
          if (new Date(today.getFullYear(), today.getMonth(), d).getDay() === day) {
            count++;
          }
        }
        return count === week;
      } else if (week === 5) {
        // Verifica se é a última ocorrência do dia no mês
        const nextWeek = new Date(today);
        nextWeek.setDate(today.getDate() + 7);
        return nextWeek.getMonth() !== today.getMonth();
      }
    }

    // Padrão semanal (ou fallback se não tiver recurringType definido)
    return task.recurringDays.includes(currentDayOfWeek);
  };

  const routineTasks = tasks.filter(isTaskDueToday);
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;

  const getSeasonCardTheme = () => {
    if (!season) return 'from-indigo-600 to-blue-700';
    const end = new Date(season.endDate);
    const diffDays = Math.ceil((end.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    const progressPercent = (season.currentPoints / season.targetPoints) * 100;

    if (diffDays <= 10) {
        if (isGoalReached) return 'from-emerald-600 to-green-700';
        else if (progressPercent < 90) return 'from-red-600 to-rose-700';
        else return 'from-amber-500 to-yellow-600';
    }
    if (isGoalReached) return 'from-yellow-500 to-orange-600';
    return 'from-indigo-600 to-blue-700';
  };

  const getRemainingDaysText = () => {
    if (!season) return "";
    const end = new Date(season.endDate);
    const diffDays = Math.ceil((end.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return "Encerrada";
    if (diffDays === 0) return "Termina hoje!";
    return `Faltam ${diffDays} dias`;
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      <style>{`
        .confetti { position: absolute; width: 8px; height: 8px; background: #ffd700; top: -10px; opacity: 0; animation: drop 3s infinite linear; }
        @keyframes drop { 0% { top: -10px; opacity: 1; transform: rotate(0deg); } 100% { top: 100%; opacity: 0; transform: rotate(360deg); } }
      `}</style>

      {season && (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${getSeasonCardTheme()}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-[10px] bg-black/20 px-2 py-0.5 rounded-full font-black uppercase tracking-tight">Até {new Date(season.endDate).toLocaleDateString('pt-BR')}</span>
                <span className="text-[10px] font-black uppercase bg-white/20 px-2 py-0.5 rounded-full shadow-sm">{getRemainingDaysText()}</span>
              </div>
            </div>
            {(isGoalReached) && (
              <button onClick={onEndSeason} className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase">Concluir Season</button>
            )}
          </div>
          <div className="space-y-2 mb-6">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} style={{ width: `${getSeasonProgress()}%` }} />
            </div>
          </div>
          {isGoalReached && (
            <div className="mt-4 p-4 bg-white/20 rounded-2xl border border-white/30 backdrop-blur-sm animate-bounce text-center" onClick={() => alert(`🎁 Prêmio: ${season.reward}`)}>
                <p className="text-[10px] font-black uppercase mb-1">🎁 Prêmio Disponível!</p>
                <p className="text-lg font-black">{season.reward}</p>
            </div>
          )}
        </section>
      )}

      <section>
        <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 mb-4"><span>📅</span> Missões de Hoje</h2>
        {routineTasks.length === 0 ? (
          <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma missão para hoje.</p>
        ) : (
          <div className="space-y-3">
            {routineTasks.map(task => (
              <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50' : 'border-blue-50'}`}>
                <div className="flex-1">
                  <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                  <div className="flex gap-2 mt-1">
                    <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black">+{task.xp} PTS</span>
                    {task.recurringType === 'monthly' && <span className="text-[9px] bg-purple-50 text-purple-600 px-1.5 py-0.5 rounded font-black">MENSAL</span>}
                  </div>
                </div>
                {!task.completed && (
                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Accordions (Loja e Falhas) seguem o padrão anterior... */}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Task } from '../types';

interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
  onReactivateTask: (id: string) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks, onReactivateTask }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);
  const [taskType, setTaskType] = useState<'recurring' | 'one-time'>('recurring');
  const [recurringType, setRecurringType] = useState<'weekly' | 'monthly'>('weekly');
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]);
  const [monthlyWeek, setMonthlyWeek] = useState(1);
  const [monthlyDay, setMonthlyDay] = useState(1);

  const daysOfWeek = [
    { id: 0, label: 'D' }, { id: 1, label: 'S' }, { id: 2, label: 'T' }, 
    { id: 3, label: 'Q' }, { id: 4, label: 'Q' }, { id: 5, label: 'S' }, { id: 6, label: 'S' }
  ];

  const weeksOfMonth = [
    { id: 1, label: '1ª' }, { id: 2, label: '2ª' }, { id: 3, label: '3ª' }, { id: 4, label: '4ª' }, { id: 5, label: 'Última' }
  ];

  const resetForm = () => {
    setNewTitle('');
    setNewXp(50);
    setNewCoins(10);
    setTaskType('recurring');
    setRecurringType('weekly');
    setSelectedDays([1, 2, 3, 4, 5]);
    setMonthlyWeek(1);
    setMonthlyDay(1);
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (task: Task) => {
    setEditingId(task.id);
    setNewTitle(task.title);
    setNewXp(task.xp);
    setNewCoins(task.coins);
    setTaskType(task.type);
    setRecurringType(task.recurringType || 'weekly');
    setSelectedDays(task.recurringDays);
    if (task.monthlyPattern) {
        setMonthlyWeek(task.monthlyPattern.week);
        setMonthlyDay(task.monthlyPattern.day);
    }
    setShowForm(true);
  };

  const saveTask = () => {
    if (!newTitle.trim()) return;

    const taskData: Task = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      type: taskType,
      recurringType: taskType === 'recurring' ? recurringType : undefined,
      recurringDays: taskType === 'recurring' && recurringType === 'weekly' ? selectedDays : [],
      monthlyPattern: taskType === 'recurring' && recurringType === 'monthly' ? { week: monthlyWeek, day: monthlyDay } : undefined,
      completionCount: 0
    };

    if (editingId) {
        onUpdateTasks(tasks.map(t => t.id === editingId ? { ...taskData, completed: t.completed, lastCompletedDate: t.lastCompletedDate, completionCount: t.completionCount } : t));
    } else {
        onUpdateTasks([taskData, ...tasks]);
    }
    resetForm();
  };

  const activeTasks = tasks.filter(t => !t.completed || t.type === 'recurring');

  return (
    <div className="p-6 pb-32">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Missões</h2>
        <button onClick={() => setShowForm(true)} className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg">+</button>
      </div>

      {showForm && (
        <div className="mb-6 bg-white p-6 rounded-3xl border border-blue-100 shadow-2xl space-y-5">
          <h3 className="font-bold text-black uppercase text-xs tracking-widest">{editingId ? 'Editar Missão' : 'Nova Missão'}</h3>

          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome da Missão</label>
              <input 
                type="text" 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
              />
            </div>

            <div className="flex gap-2">
                <button onClick={() => setTaskType('recurring')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl border-2 transition-all ${taskType === 'recurring' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>Rotina</button>
                <button onClick={() => setTaskType('one-time')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl border-2 transition-all ${taskType === 'one-time' ? 'bg-purple-600 border-purple-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>Pontual</button>
            </div>

            {taskType === 'recurring' && (
              <div className="space-y-4 pt-2 border-t border-slate-50">
                <div className="flex bg-slate-50 p-1 rounded-xl">
                    <button onClick={() => setRecurringType('weekly')} className={`flex-1 py-1.5 text-[9px] font-black uppercase rounded-lg ${recurringType === 'weekly' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Semanal</button>
                    <button onClick={() => setRecurringType('monthly')} className={`flex-1 py-1.5 text-[9px] font-black uppercase rounded-lg ${recurringType === 'monthly' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Mensal</button>
                </div>

                {recurringType === 'weekly' ? (
                  <div className="flex justify-between">
                    {daysOfWeek.map(day => (
                      <button
                        key={day.id}
                        onClick={() => setSelectedDays(prev => prev.includes(day.id) ? prev.filter(d => d !== day.id) : [...prev, day.id])}
                        className={`w-8 h-8 rounded-full text-[10px] font-bold transition-all ${selectedDays.includes(day.id) ? 'bg-blue-600 text-white' : 'bg-white border-2 border-slate-100 text-slate-400'}`}
                      >
                        {day.label}
                      </button>
                    ))}
                  </div>
                ) : (
                  <div className="space-y-3">
                    <div className="flex justify-between gap-1">
                      {weeksOfMonth.map(w => (
                        <button key={w.id} onClick={() => setMonthlyWeek(w.id)} className={`flex-1 py-2 rounded-xl text-[9px] font-bold border-2 ${monthlyWeek === w.id ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-400'}`}>{w.label}</button>
                      ))}
                    </div>
                    <div className="flex justify-between gap-1">
                      {daysOfWeek.map(d => (
                        <button key={d.id} onClick={() => setMonthlyDay(d.id)} className={`w-8 h-8 rounded-xl text-[10px] font-bold border-2 ${monthlyDay === d.id ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-400'}`}>{d.label}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Pts Season</label>
                <input type="number" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" value={newXp} onChange={e => setNewXp(parseInt(e.target.value))} />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Moedas 🪙</label>
                <input type="number" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold text-green-600" value={newCoins} onChange={e => setNewCoins(parseInt(e.target.value))} />
              </div>
            </div>

            <div className="flex gap-2 pt-4">
              <button onClick={resetForm} className="flex-1 py-4 text-slate-400 font-black text-[10px] uppercase">Cancelar</button>
              <button onClick={saveTask} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg">Salvar</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {activeTasks.map(task => (
          <div key={task.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
            <div className="flex-1 min-w-0 pr-4">
              <span className="block font-bold text-slate-700 truncate">{task.title}</span>
              <div className="flex items-center gap-2 mt-1">
                <span className={`text-[8px] px-1.5 py-0.5 rounded font-black uppercase ${task.type === 'one-time' ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'}`}>
                    {task.recurringType === 'monthly' ? 'Mensal' : task.type === 'one-time' ? 'Pontual' : 'Rotina'}
                </span>
                <span className="text-[9px] text-slate-400 font-bold">{task.xp} pts | {task.coins} 🪙</span>
              </div>
            </div>
            <div className="flex gap-1">
                <button onClick={() => handleEdit(task)} className="p-2 text-blue-400 hover:bg-blue-50 rounded-lg transition-colors">✏️</button>
                <button onClick={() => onUpdateTasks(tasks.filter(t => t.id !== task.id))} className="p-2 text-red-200 hover:text-red-500 rounded-lg transition-colors">🗑️</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TaskManager;

import React, { useState } from 'react';
import { Punishment } from '../types';

interface PunishmentManagerProps {
