import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  // Estados para o formulário de nova temporada
  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const defaultDate = new Date();
    defaultDate.setMonth(defaultDate.getMonth() + 1);
    return defaultDate.toISOString().split('T')[0];
  });

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentDayOfWeek = today.getDay();
  const currentDateNum = today.getDate();

  const isTaskDueToday = (task: Task) => {
    if (task.completed && task.lastCompletedDate === todayStr) return true;
    if (task.type === 'one-time') return !task.completed;
    if (task.recurringType === 'monthly' && task.monthlyPattern) {
      const { week, day } = task.monthlyPattern;
      if (currentDayOfWeek !== day) return false;
      if (week <= 4) {
        const firstDayOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);
        let count = 0;
        for (let d = 1; d <= currentDateNum; d++) {
          if (new Date(today.getFullYear(), today.getMonth(), d).getDay() === day) count++;
        }
        return count === week;
      } else if (week === 5) {
        const nextWeek = new Date(today);
        nextWeek.setDate(today.getDate() + 7);
        return nextWeek.getMonth() !== today.getMonth();
      }
    }
    return task.recurringDays.includes(currentDayOfWeek);
  };

  const routineTasks = tasks.filter(isTaskDueToday);
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;

  const getSeasonCardTheme = () => {
    if (!season) return 'from-indigo-600 to-blue-700';
    const end = new Date(season.endDate);
    const diffDays = Math.ceil((end.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    const progressPercent = (season.currentPoints / season.targetPoints) * 100;

    if (diffDays <= 10) {
        if (isGoalReached) return 'from-emerald-600 to-green-700';
        else if (progressPercent < 90) return 'from-red-600 to-rose-700';
        else return 'from-amber-500 to-yellow-600';
    }
    if (isGoalReached) return 'from-yellow-500 to-orange-600';
    return 'from-indigo-600 to-blue-700';
  };

  const getRemainingDaysText = () => {
    if (!season) return "";
    const end = new Date(season.endDate);
    const diffDays = Math.ceil((end.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return "Encerrada";
    if (diffDays === 0) return "Termina hoje!";
    return `Faltam ${diffDays} dias`;
  };

  const createSeason = () => {
    if (!newSName || !newSReward || !newSEndDate) {
      alert("Preencha todos os campos da temporada!");
      return;
    }
    const newSeason: Season = {
      id: Math.random().toString(36).substr(2, 9),
      title: newSName,
      startDate: new Date().toISOString(),
      endDate: new Date(newSEndDate + 'T23:59:59').toISOString(),
      targetPoints: newSTarget,
      currentPoints: 0,
      reward: newSReward,
      isActive: true,
      seasonNumber: 0
    };
    onCreateSeason(newSeason);
    setNewSName('');
    setNewSReward('');
  };

  return (
    <div className="p-6 space-y-6 relative overflow-hidden">
      <style>{`
        .confetti { position: absolute; width: 8px; height: 8px; background: #ffd700; top: -10px; opacity: 0; animation: drop 3s infinite linear; }
        @keyframes drop { 0% { top: -10px; opacity: 1; transform: rotate(0deg); } 100% { top: 100%; opacity: 0; transform: rotate(360deg); } }
      `}</style>

      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 shadow-sm">
          <div className="text-center mb-6">
            <span className="text-4xl block mb-2">🏆</span>
            <h3 className="font-bold text-slate-800 text-lg">Nova Temporada</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Defina seu próximo grande objetivo</p>
          </div>

          <div className="space-y-4 text-left">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título da Season</label>
              <input 
                placeholder="Ex: Foco Total, Verão 2024..." 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium"
                value={newSName} onChange={e => setNewSName(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta de Pontos</label>
                <input 
                  type="number" 
                  className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold focus:outline-none focus:border-blue-400"
                  value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input 
                  type="date" 
                  className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold focus:outline-none focus:border-blue-400"
                  value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)}
                />
              </div>
            </div>

            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Recompensa Final (Prêmio)</label>
              <input 
                placeholder="O que você ganhará ao vencer?" 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium"
                value={newSReward} onChange={e => setNewSReward(e.target.value)}
              />
            </div>

            <button 
              onClick={createSeason} 
              className="w-full py-4 mt-2 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg active:scale-95 transition-transform"
            >
              Iniciar Temporada
            </button>
          </div>
        </section>
      ) : (
        <section className={`relative bg-gradient-to-br transition-all duration-500 rounded-3xl p-6 text-white shadow-xl z-10 ${getSeasonCardTheme()}`}>
          <div className="flex justify-between items-start mb-6">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold">{season.title}</h3>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-[10px] bg-black/20 px-2 py-0.5 rounded-full font-black uppercase tracking-tight">Até {new Date(season.endDate).toLocaleDateString('pt-BR')}</span>
                <span className="text-[10px] font-black uppercase bg-white/20 px-2 py-0.5 rounded-full shadow-sm">{getRemainingDaysText()}</span>
              </div>
            </div>
            {isGoalReached && (
              <button onClick={onEndSeason} className="bg-black/20 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase">Concluir Season</button>
