                  <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>
                )}
                {task.completed && <span className="text-green-500 font-bold px-3">✓</span>}
              </div>
            ))}
          </div>
        )}
      </section>

      <div className="space-y-3 pb-8">
        <section className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20">
            <div className="flex items-center gap-2">
