import Navbar from './components/Navbar';

const APP_ICON = "https://i.ibb.co/C386YvW/patrick-pixel.png";

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        return t;
      });
      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    return {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    } as HistoryEntry;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [addHistoryEntry('task', task.title, task.xp, task.id), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun) return;

    // Trava para registro único por dia
    if (pun.lastAppliedDate === today) {
      alert(`⚠️ Esta falha ("${pun.title}") já foi registrada hoje!`);
      return;
    }

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    const historyTitle = `Fim da Season #${data.currentSeason.seasonNumber}: ${isSuccess ? 'Sucesso' : 'Incompleta'}`;

    setData({ 
      ...data, 
      currentSeason: null,
      history: [addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints), ...data.history]
    });
    alert(isSuccess ? "🏆 PARABÉNS! Season concluída com sucesso!" : "❌ Season encerrada sem atingir a meta.");
  };

  const handleReset = () => {
    if (confirm('Deseja resetar tudo?')) {
      localStorage.removeItem('gami_routine_data');
      setData(INITIAL_DATA);
    }
  };

  const isNegative = data.stats.totalCoins < 0;

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div className="flex items-center gap-3">
          <img src={APP_ICON} className="w-12 h-12 rounded-full border-2 border-blue-100 shadow-md object-cover" alt="Logo" />
          <div>
            <h1 className="text-xl font-bold text-blue-600 leading-tight">Patrick's Life</h1>
            <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
          </div>
        </div>
        <div className="flex flex-col items-end gap-1">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-all ${isNegative ? 'bg-red-50 border-red-300' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-black ${isNegative ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} tasks={data.tasks} rewards={data.rewards} punishments={data.punishments} season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={(id) => {
              const r = data.rewards.find(x => x.id === id);
              if (r && data.stats.totalCoins >= r.cost) {
                setData(prev => ({...prev, stats: {...prev.stats, totalCoins: prev.stats.totalCoins - r.cost}, history: [addHistoryEntry('reward', r.title, r.cost), ...prev.history]}));
              }
            }}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && <TaskManager tasks={data.tasks} onUpdateTasks={(tasks) => setData({...data, tasks})} onReactivateTask={() => {}} />}
        {currentView === 'shop' && <RewardShop rewards={data.rewards} coins={data.stats.totalCoins} onUpdateRewards={(rewards) => setData({...data, rewards})} onPurchase={(id) => {}} />}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={() => {}} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} onReset={handleReset} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);
  const [isShopOpen, setIsShopOpen] = useState(false);
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);

  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const d = new Date();
    d.setMonth(d.getMonth() + 1);
    return d.toISOString().split('T')[0];
  });

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentDayOfWeek = today.getDay();
  const currentDateNum = today.getDate();

  const isTaskDueToday = (task: Task) => {
    if (task.completed && task.lastCompletedDate === todayStr) return true;
    if (task.type === 'one-time') return !task.completed;
    if (task.recurringType === 'monthly' && task.monthlyPattern) {
      const { week, day } = task.monthlyPattern;
      if (currentDayOfWeek !== day) return false;
      if (week <= 4) {
        let count = 0;
        for (let d = 1; d <= currentDateNum; d++) {
          if (new Date(today.getFullYear(), today.getMonth(), d).getDay() === day) count++;
        }
        return count === week;
      } else if (week === 5) {
        const nextWeek = new Date(today);
        nextWeek.setDate(today.getDate() + 7);
        return nextWeek.getMonth() !== today.getMonth();
      }
    }
    return (task.recurringDays || []).includes(currentDayOfWeek);
  };

  const routineTasks = tasks.filter(isTaskDueToday);
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isNegative = stats.totalCoins < 0;

  return (
    <div className="p-6 space-y-6">
      {/* Seção de Temporada / Início */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 shadow-sm">
          <div className="text-center mb-6">
            <span className="text-4xl block mb-2">🏆</span>
            <h3 className="font-bold text-slate-800 text-lg">Nova Temporada</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Defina seu próximo grande objetivo</p>
          </div>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título</label>
              <input value={newSName} onChange={e => setNewSName(e.target.value)} placeholder="Ex: Foco Total..." className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta XP</label>
                <input type="number" value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Fim</label>
                <input type="date" value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Prêmio Final</label>
              <input value={newSReward} onChange={e => setNewSReward(e.target.value)} placeholder="O que você ganhará?" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-medium" />
            </div>
            <button onClick={() => onCreateSeason({id: Math.random().toString(36).substr(2, 9), title: newSName, startDate: new Date().toISOString(), endDate: newSEndDate, targetPoints: newSTarget, currentPoints: 0, reward: newSReward, isActive: true, seasonNumber: 0})} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg">Iniciar Temporada</button>
          </div>
        </section>
      ) : (
        <section className={`rounded-3xl p-6 text-white shadow-xl bg-gradient-to-br ${isGoalReached ? 'from-emerald-600 to-green-700' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-4">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold truncate">{season.title}</h3>
            </div>
            {isGoalReached && (
              <button onClick={onEndSeason} className="bg-white/20 px-3 py-1 rounded-full text-[10px] font-black uppercase backdrop-blur-sm">Concluir</button>
            )}
          </div>
          <div className="space-y-2">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} style={{ width: `${getSeasonProgress()}%` }} />
            </div>
          </div>
        </section>
      )}

      {/* Alerta de Saldo Negativo - Banner Pequeno */}
      {isNegative && (
        <div className="bg-red-50 border border-red-200 rounded-2xl p-3 flex items-center gap-3 animate-pulse">
            <span className="text-xl">⚠️</span>
            <div>
                <p className="text-[10px] font-black text-red-600 uppercase tracking-widest">Saldo Negativo</p>
                <p className="text-[11px] text-red-500 font-bold leading-tight">Você possui {Math.abs(stats.totalCoins)} moedas em dívida. Foque nas missões!</p>
            </div>
        </div>
      )}

      <section>
        <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2 mb-4"><span>📅</span> Missões de Hoje</h2>
        <div className="space-y-3">
          {routineTasks.length === 0 ? <p className="text-xs text-slate-400 p-4 bg-white rounded-2xl border border-blue-50">Nenhuma missão pendente.</p> : routineTasks.map(task => (
            <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm ${task.completed ? 'opacity-50 grayscale' : 'border-blue-50'}`}>
              <div className="flex-1">
                <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                <div className="flex gap-2 mt-1">
                  <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black uppercase">+{task.xp} XP</span>
                  <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black uppercase">🪙 {task.coins}</span>
                </div>
              </div>
              {!task.completed && <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold">✓</button>}
              {task.completed && <span className="text-green-500 font-bold px-3">OK</span>}
            </div>
          ))}
        </div>
      </section>

      <div className="space-y-3 pb-8">
        <section className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas</span>
            </div>
            <span className={`transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100">
              {punishments.map(p => (
                <div key={p.id} className="flex items-center justify-between p-3 rounded-xl border bg-orange-50/50 border-orange-100">
                  <span className="text-xs font-bold text-slate-700">{p.title} (-{p.cost}🪙)</span>
                  <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase">Registrar</button>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  // Estados para controlar o que está aberto ou fechado
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);
  const [isRewardsOpen, setIsRewardsOpen] = useState(false);
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);

  // Estados para o formulário de nova temporada
  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const d = new Date();
    d.setMonth(d.getMonth() + 1);
    return d.toISOString().split('T')[0];
  });

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentDayOfWeek = today.getDay();
  const currentDateNum = today.getDate();

  const isTaskDueToday = (task: Task) => {
    if (task.type === 'one-time') return false; // Pontuais ficam em outra seção
    if (task.completed && task.lastCompletedDate === todayStr) return true;

    if (task.recurringType === 'monthly' && task.monthlyPattern) {
      const { week, day } = task.monthlyPattern;
      if (currentDayOfWeek !== day) return false;
      if (week <= 4) {
        let count = 0;
        for (let d = 1; d <= currentDateNum; d++) {
          if (new Date(today.getFullYear(), today.getMonth(), d).getDay() === day) count++;
        }
        return count === week;
      } else if (week === 5) {
        const nextWeek = new Date(today);
        nextWeek.setDate(today.getDate() + 7);
        return nextWeek.getMonth() !== today.getMonth();
      }
    }
    return (task.recurringDays || []).includes(currentDayOfWeek);
  };

  const routineTasks = tasks.filter(isTaskDueToday);
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isNegative = stats.totalCoins < 0;

  return (
    <div className="p-6 space-y-4">
      {/* 1. SEÇÃO DE TEMPORADA */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 shadow-sm">
          <div className="text-center mb-6">
            <span className="text-4xl block mb-2">🏆</span>
            <h3 className="font-bold text-slate-800 text-lg">Nova Temporada</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Defina seu próximo grande objetivo</p>
          </div>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título da Season</label>
              <input value={newSName} onChange={e => setNewSName(e.target.value)} placeholder="Ex: Foco Total..." className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta XP</label>
                <input type="number" value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input type="date" value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Recompensa (Prêmio)</label>
              <input value={newSReward} onChange={e => setNewSReward(e.target.value)} placeholder="O que você ganhará?" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-medium" />
            </div>
            <button onClick={() => onCreateSeason({id: Math.random().toString(36).substr(2, 9), title: newSName, startDate: new Date().toISOString(), endDate: newSEndDate, targetPoints: newSTarget, currentPoints: 0, reward: newSReward, isActive: true, seasonNumber: 0})} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg active:scale-95 transition-transform">Iniciar Temporada</button>
          </div>
        </section>
      ) : (
        <section className={`rounded-3xl p-6 text-white shadow-xl bg-gradient-to-br ${isGoalReached ? 'from-emerald-600 to-green-700' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-4">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold truncate">{season.title}</h3>
            </div>
            {isGoalReached && (
              <button onClick={onEndSeason} className="bg-white/20 px-3 py-1 rounded-full text-[10px] font-black uppercase backdrop-blur-sm">Concluir</button>
            )}
          </div>
          <div className="space-y-2">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} style={{ width: `${getSeasonProgress()}%` }} />
            </div>
          </div>
        </section>
      )}

      {/* 2. ALERTA DE SALDO NEGATIVO (Banner abaixo do card de season) */}
      {isNegative && (
        <div className="bg-red-50 border border-red-200 rounded-2xl p-3 flex items-center gap-3 animate-pulse shadow-sm">
            <span className="text-xl">⚠️</span>
            <div className="flex-1">
                <p className="text-[10px] font-black text-red-600 uppercase tracking-widest leading-none mb-1">Dívida de Moedas!</p>
                <p className="text-[11px] text-red-500 font-bold leading-tight">Você está com {stats.totalCoins} 🪙. Complete missões para sair do vermelho!</p>
            </div>
        </div>
      )}

      {/* 3. MISSÕES DE ROTINA (Sempre Visível) */}
      <section className="pt-2">
        <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-3 flex items-center gap-2">
          <span className="text-lg">📅</span> Rotina de Hoje
        </h2>
        <div className="space-y-3">
          {routineTasks.length === 0 ? (
            <div className="bg-white/50 p-6 rounded-3xl border border-dashed border-blue-100 text-center">
               <p className="text-xs text-slate-400 font-medium italic">Nenhuma missão de rotina para hoje.</p>
            </div>
          ) : routineTasks.map(task => (
            <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50 grayscale' : 'border-blue-50'}`}>
              <div className="flex-1">
                <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
