            <span className={`text-purple-300 transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100 bg-purple-50/10">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Nenhuma missão pontual pendente.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-purple-50 shadow-sm">
                    <div>
                      <span className="block text-xs font-bold text-slate-700">{task.title}</span>
                      <span className="text-[9px] font-black text-purple-600 uppercase">+{task.xp} XP | {task.coins} 🪙</span>
                    </div>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </div>

        {/* 5. RECOMPENSAS / LOJA */}
        <div className="bg-white rounded-2xl border border-emerald-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsRewardsOpen(!isRewardsOpen)} className="w-full p-4 flex justify-between items-center bg-emerald-50/20 active:bg-emerald-50 transition-colors">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎁</span>
              <span className="font-bold text-emerald-800 text-sm">Resgates Disponíveis</span>
              {affordableRewards.length > 0 && <span className="bg-emerald-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-full">{affordableRewards.length}</span>}
            </div>
            <span className={`text-emerald-300 transform transition-transform ${isRewardsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isRewardsOpen && (
            <div className="p-4 space-y-3 border-t border-emerald-100 bg-emerald-50/10">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Você ainda não tem moedas suficientes para resgates.</p>
              ) : (
                affordableRewards.map(reward => (
                  <div key={reward.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-emerald-50 shadow-sm">
                    <div>
                      <span className="block text-xs font-bold text-slate-700">{reward.title}</span>
                      <span className="text-[10px] font-black text-emerald-600 uppercase">Custo: {reward.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(reward.id)} className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </div>

        {/* 6. FALHAS / PUNIÇÕES */}
        <div className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20 active:bg-orange-50 transition-colors">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas</span>
            </div>
            <span className={`text-orange-300 transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100 bg-orange-50/10">
              {punishments.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Cadastre falhas na aba "Punir".</p>
              ) : (
                punishments.map(p => (
                  <div key={p.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-orange-100 shadow-sm">
                    <div>
                      <span className="block text-xs font-bold text-slate-700">{p.title}</span>
                      <span className="text-[10px] font-black text-orange-600 uppercase">Multa: -{p.cost} 🪙</span>
                    </div>
                    <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Registrar</button>
                  </div>
                ))
              )}
              <p className="text-[8px] text-center text-slate-400 font-bold uppercase tracking-tight">Cada falha só pode ser registrada uma vez por dia.</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Task, Reward, Punishment, UserStats, Season } from '../types';

interface DashboardProps {
  stats: UserStats;
  tasks: Task[];
  rewards: Reward[];
  punishments: Punishment[];
  season: Season | null;
  onCompleteTask: (id: string) => void;
  onPurchaseReward: (id: string) => void;
  onApplyPunishment: (id: string) => void;
  onCreateSeason: (season: Season) => void;
  onEndSeason: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ stats, tasks, rewards, punishments, season, onCompleteTask, onPurchaseReward, onApplyPunishment, onCreateSeason, onEndSeason }) => {
  // Estados para controlar o que está aberto ou fechado
  const [isOneTimeOpen, setIsOneTimeOpen] = useState(false);
  const [isRewardsOpen, setIsRewardsOpen] = useState(false);
  const [isPunishmentsOpen, setIsPunishmentsOpen] = useState(false);

  // Estados para o formulário de nova temporada
  const [newSName, setNewSName] = useState('');
  const [newSTarget, setNewSTarget] = useState(5000);
  const [newSReward, setNewSReward] = useState('');
  const [newSEndDate, setNewSEndDate] = useState(() => {
    const d = new Date();
    d.setMonth(d.getMonth() + 1);
    return d.toISOString().split('T')[0];
  });

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const currentDayOfWeek = today.getDay();
  const currentDateNum = today.getDate();

  const isTaskDueToday = (task: Task) => {
    if (task.type === 'one-time') return false; // Pontuais ficam em outra seção
    if (task.completed && task.lastCompletedDate === todayStr) return true;

    if (task.recurringType === 'monthly' && task.monthlyPattern) {
      const { week, day } = task.monthlyPattern;
      if (currentDayOfWeek !== day) return false;
      if (week <= 4) {
        let count = 0;
        for (let d = 1; d <= currentDateNum; d++) {
          if (new Date(today.getFullYear(), today.getMonth(), d).getDay() === day) count++;
        }
        return count === week;
      } else if (week === 5) {
        const nextWeek = new Date(today);
        nextWeek.setDate(today.getDate() + 7);
        return nextWeek.getMonth() !== today.getMonth();
      }
    }
    return (task.recurringDays || []).includes(currentDayOfWeek);
  };

  const routineTasks = tasks.filter(isTaskDueToday);
  const oneTimeTasks = tasks.filter(t => t.type === 'one-time' && !t.completed);
  const affordableRewards = rewards.filter(r => r.cost <= stats.totalCoins);

  const getSeasonProgress = () => {
    if (!season) return 0;
    return Math.min(100, (season.currentPoints / season.targetPoints) * 100);
  };

  const isGoalReached = season ? season.currentPoints >= season.targetPoints : false;
  const isNegative = stats.totalCoins < 0;

  return (
    <div className="p-6 space-y-4">
      {/* 1. SEÇÃO DE TEMPORADA */}
      {!season ? (
        <section className="bg-white rounded-3xl p-6 border-2 border-dashed border-blue-200 shadow-sm">
          <div className="text-center mb-6">
            <span className="text-4xl block mb-2">🏆</span>
            <h3 className="font-bold text-slate-800 text-lg">Nova Temporada</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Defina seu próximo grande objetivo</p>
          </div>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título da Season</label>
              <input value={newSName} onChange={e => setNewSName(e.target.value)} placeholder="Ex: Foco Total..." className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Meta XP</label>
                <input type="number" value={newSTarget} onChange={e => setNewSTarget(parseInt(e.target.value) || 0)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Fim</label>
                <input type="date" value={newSEndDate} onChange={e => setNewSEndDate(e.target.value)} className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" />
              </div>
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Recompensa (Prêmio)</label>
              <input value={newSReward} onChange={e => setNewSReward(e.target.value)} placeholder="O que você ganhará?" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-medium" />
            </div>
            <button onClick={() => onCreateSeason({id: Math.random().toString(36).substr(2, 9), title: newSName, startDate: new Date().toISOString(), endDate: newSEndDate, targetPoints: newSTarget, currentPoints: 0, reward: newSReward, isActive: true, seasonNumber: 0})} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg active:scale-95 transition-transform">Iniciar Temporada</button>
          </div>
        </section>
      ) : (
        <section className={`rounded-3xl p-6 text-white shadow-xl bg-gradient-to-br ${isGoalReached ? 'from-emerald-600 to-green-700' : 'from-indigo-600 to-blue-700'}`}>
          <div className="flex justify-between items-start mb-4">
            <div>
              <p className="text-[10px] font-black uppercase opacity-70 tracking-widest mb-1">Temporada #{season.seasonNumber}</p>
              <h3 className="text-2xl font-bold truncate">{season.title}</h3>
            </div>
            {isGoalReached && (
              <button onClick={onEndSeason} className="bg-white/20 px-3 py-1 rounded-full text-[10px] font-black uppercase backdrop-blur-sm">Concluir</button>
            )}
          </div>
          <div className="space-y-2">
            <div className="flex justify-between text-xs font-bold uppercase">
              <span>{season.currentPoints} pts</span>
              <span className="opacity-60">Meta: {season.targetPoints}</span>
            </div>
            <div className="w-full bg-black/20 rounded-full h-4 p-1 overflow-hidden shadow-inner">
              <div className={`h-full rounded-full transition-all duration-1000 ease-out ${isGoalReached ? 'bg-white' : 'bg-yellow-400'}`} style={{ width: `${getSeasonProgress()}%` }} />
            </div>
          </div>
        </section>
      )}

      {/* 2. ALERTA DE SALDO NEGATIVO (Banner abaixo do card de season) */}
      {isNegative && (
        <div className="bg-red-50 border border-red-200 rounded-2xl p-3 flex items-center gap-3 animate-pulse shadow-sm">
            <span className="text-xl">⚠️</span>
            <div className="flex-1">
                <p className="text-[10px] font-black text-red-600 uppercase tracking-widest leading-none mb-1">Dívida de Moedas!</p>
                <p className="text-[11px] text-red-500 font-bold leading-tight">Você está com {stats.totalCoins} 🪙. Complete missões para sair do vermelho!</p>
            </div>
        </div>
      )}

      {/* 3. MISSÕES DE ROTINA (Sempre Visível) */}
      <section className="pt-2">
        <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-1 mb-3 flex items-center gap-2">
          <span className="text-lg">📅</span> Rotina de Hoje
        </h2>
        <div className="space-y-3">
          {routineTasks.length === 0 ? (
            <div className="bg-white/50 p-6 rounded-3xl border border-dashed border-blue-100 text-center">
               <p className="text-xs text-slate-400 font-medium italic">Nenhuma missão de rotina para hoje.</p>
            </div>
          ) : routineTasks.map(task => (
            <div key={task.id} className={`bg-white p-4 rounded-2xl flex items-center justify-between border shadow-sm transition-all ${task.completed ? 'opacity-50 grayscale' : 'border-blue-50'}`}>
              <div className="flex-1">
                <span className={`block font-bold text-slate-700 ${task.completed ? 'line-through' : ''}`}>{task.title}</span>
                <div className="flex gap-2 mt-1">
                  <span className="text-[9px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-black uppercase">+{task.xp} XP</span>
                  <span className="text-[9px] bg-yellow-50 text-yellow-600 px-1.5 py-0.5 rounded font-black uppercase">🪙 {task.coins}</span>
                </div>
              </div>
              {!task.completed && (
                <button onClick={() => onCompleteTask(task.id)} className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 border border-blue-100 flex items-center justify-center font-bold active:bg-blue-600 active:text-white">✓</button>
              )}
              {task.completed && <span className="text-green-500 font-bold px-3">OK</span>}
            </div>
          ))}
        </div>
      </section>

      {/* SEÇÕES OCULTAS (COLLAPSIBLES) */}
      <div className="space-y-2 pb-10">

        {/* 4. MISSÕES PONTUAIS */}
        <div className="bg-white rounded-2xl border border-purple-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsOneTimeOpen(!isOneTimeOpen)} className="w-full p-4 flex justify-between items-center bg-purple-50/20 active:bg-purple-50 transition-colors">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎯</span>
              <span className="font-bold text-purple-800 text-sm">Missões Pontuais</span>
              {oneTimeTasks.length > 0 && <span className="bg-purple-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-full">{oneTimeTasks.length}</span>}
            </div>
            <span className={`text-purple-300 transform transition-transform ${isOneTimeOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isOneTimeOpen && (
            <div className="p-4 space-y-3 border-t border-purple-100 bg-purple-50/10">
              {oneTimeTasks.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Nenhuma missão pontual pendente.</p>
              ) : (
                oneTimeTasks.map(task => (
                  <div key={task.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-purple-50 shadow-sm">
                    <div>
                      <span className="block text-xs font-bold text-slate-700">{task.title}</span>
                      <span className="text-[9px] font-black text-purple-600 uppercase">+{task.xp} XP | {task.coins} 🪙</span>
                    </div>
                    <button onClick={() => onCompleteTask(task.id)} className="bg-purple-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Concluir</button>
                  </div>
                ))
              )}
            </div>
          )}
        </div>

        {/* 5. RECOMPENSAS / LOJA */}
        <div className="bg-white rounded-2xl border border-emerald-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsRewardsOpen(!isRewardsOpen)} className="w-full p-4 flex justify-between items-center bg-emerald-50/20 active:bg-emerald-50 transition-colors">
            <div className="flex items-center gap-2">
              <span className="text-lg">🎁</span>
              <span className="font-bold text-emerald-800 text-sm">Resgates Disponíveis</span>
              {affordableRewards.length > 0 && <span className="bg-emerald-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-full">{affordableRewards.length}</span>}
            </div>
            <span className={`text-emerald-300 transform transition-transform ${isRewardsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isRewardsOpen && (
            <div className="p-4 space-y-3 border-t border-emerald-100 bg-emerald-50/10">
              {affordableRewards.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Você ainda não tem moedas suficientes para resgates.</p>
              ) : (
                affordableRewards.map(reward => (
                  <div key={reward.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-emerald-50 shadow-sm">
                    <div>
                      <span className="block text-xs font-bold text-slate-700">{reward.title}</span>
                      <span className="text-[10px] font-black text-emerald-600 uppercase">Custo: {reward.cost} 🪙</span>
                    </div>
                    <button onClick={() => onPurchaseReward(reward.id)} className="bg-emerald-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Resgatar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </div>

        {/* 6. FALHAS / PUNIÇÕES */}
        <div className="bg-white rounded-2xl border border-orange-100 overflow-hidden shadow-sm">
          <button onClick={() => setIsPunishmentsOpen(!isPunishmentsOpen)} className="w-full p-4 flex justify-between items-center bg-orange-50/20 active:bg-orange-50 transition-colors">
            <div className="flex items-center gap-2">
              <span className="text-lg">⚖️</span>
              <span className="font-bold text-orange-800 text-sm">Registrar Falhas</span>
            </div>
            <span className={`text-orange-300 transform transition-transform ${isPunishmentsOpen ? 'rotate-180' : ''}`}>▼</span>
          </button>
          {isPunishmentsOpen && (
            <div className="p-4 space-y-3 border-t border-orange-100 bg-orange-50/10">
              {punishments.length === 0 ? (
                <p className="text-[10px] text-slate-400 text-center py-2 font-medium">Cadastre falhas na aba "Punir".</p>
              ) : (
                punishments.map(p => {
                  const isAppliedToday = p.lastAppliedDate === todayStr;
                  return (
                    <div key={p.id} className={`flex items-center justify-between p-3 bg-white rounded-xl border border-orange-100 shadow-sm transition-all ${isAppliedToday ? 'opacity-50 grayscale' : ''}`}>
                      <div className="flex-1 min-w-0 pr-2">
                        <span className={`block text-xs font-bold text-slate-700 ${isAppliedToday ? 'line-through' : ''} truncate`}>{p.title}</span>
                        <span className="text-[10px] font-black text-orange-600 uppercase">Multa: -{p.cost} 🪙</span>
                      </div>
                      {isAppliedToday ? (
                        <span className="text-orange-600 font-bold px-3 text-[10px]">OK</span>
                      ) : (
                        <button onClick={() => onApplyPunishment(p.id)} className="bg-orange-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase shadow-sm active:scale-95">Registrar</button>
                      )}
                    </div>
                  );
                })
              )}
              <p className="text-[8px] text-center text-slate-400 font-bold uppercase tracking-tight">Cada falha só pode ser registrada uma vez por dia.</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Punishment } from '../types';

interface PunishmentManagerProps {
  punishments: Punishment[];
  onUpdatePunishments: (punishments: Punishment[]) => void;
  onApply: (id: string) => void;
}

const PunishmentManager: React.FC<PunishmentManagerProps> = ({ punishments, onUpdatePunishments, onApply }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newCost, setNewCost] = useState(50);

  const todayStr = new Date().toISOString().split('T')[0];

  const resetForm = () => {
    setNewTitle('');
    setNewCost(50);
    setEditingId(null);
    setShowForm(false);
  };

  const savePunishment = () => {
    if (!newTitle.trim()) return;
    const punData: Punishment = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      title: newTitle,
      cost: newCost
    };

    if (editingId) {
        onUpdatePunishments(punishments.map(p => p.id === editingId ? { ...punData, lastAppliedDate: p.lastAppliedDate } : p));
    } else {
        onUpdatePunishments([...punishments, punData]);
    }
    resetForm();
  };

  const handleEdit = (pun: Punishment) => {
    setEditingId(pun.id);
    setNewTitle(pun.title);
    setNewCost(pun.cost);
    setShowForm(true);
  };

  return (
    <div className="p-6 pb-32">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Câmara de Punições</h2>
          <p className="text-xs text-red-500 font-medium">Falhar tem um preço...</p>
        </div>
        <button 
          onClick={() => setShowForm(true)}
          className="bg-orange-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg"
        >
          +
        </button>
      </div>

      {showForm && (
        <div className="mb-6 bg-white p-6 rounded-3xl border border-orange-100 shadow-xl space-y-4">
          <h3 className="font-bold text-black uppercase text-xs tracking-widest">{editingId ? 'Editar Punição' : 'Nova Punição'}</h3>

          <div className="space-y-3">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Título da Falha</label>
              <input 
                type="text" 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-orange-400 font-medium"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Custo (Perda 🪙)</label>
              <input 
                type="number" 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold text-red-600"
                value={newCost}
                onChange={(e) => setNewCost(parseInt(e.target.value) || 0)}
              />
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <button onClick={resetForm} className="flex-1 py-3 text-slate-400 font-black text-[10px] uppercase">Cancelar</button>
            <button onClick={savePunishment} className="flex-1 py-3 bg-orange-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-md">Salvar</button>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {punishments.map(p => {
          const isAppliedToday = p.lastAppliedDate === todayStr;
          return (
            <div key={p.id} className={`bg-white p-4 rounded-2xl border border-orange-50 shadow-sm flex items-center gap-4 transition-all ${isAppliedToday ? 'opacity-50 grayscale' : ''}`}>
              <div className="w-10 h-10 bg-orange-50 rounded-full flex items-center justify-center text-lg">⚠️</div>
              <div className="flex-1 min-w-0">
                <span className={`block font-bold text-slate-700 ${isAppliedToday ? 'line-through' : ''} truncate`}>{p.title}</span>
                <span className="text-xs font-bold text-orange-600">-{p.cost} Moedas</span>
              </div>
              <div className="flex items-center gap-1">
                  {!isAppliedToday && <button onClick={() => handleEdit(p)} className="p-2 text-blue-400 hover:bg-blue-50 rounded-lg">✏️</button>}
                  {isAppliedToday ? (
                    <span className="text-orange-500 font-black px-3 text-[10px] uppercase">OK</span>
                  ) : (
                    <button onClick={() => onApply(p.id)} className="bg-orange-500 text-white px-3 py-1.5 rounded-xl text-[10px] font-black uppercase shadow-sm active:scale-95">Falhei</button>
                  )}
                  <button onClick={() => onUpdatePunishments(punishments.filter(pun => pun.id !== p.id))} className="p-2 text-slate-300 hover:text-red-500 transition-colors">🗑️</button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PunishmentManager;

import React, { useState, useEffect } from 'react';
import { View, Task, Reward, Punishment, HistoryEntry, AppData, Season } from './types';
import Dashboard from './components/Dashboard';
import TaskManager from './components/TaskManager';
import RewardShop from './components/RewardShop';
import PunishmentManager from './components/PunishmentManager';
import HistoryManager from './components/HistoryManager';
import Settings from './components/Settings';
import Navbar from './components/Navbar';

const APP_ICON = "https://i.ibb.co/C386YvW/patrick-pixel.png";

const INITIAL_DATA: AppData = {
  tasks: [],
  rewards: [],
  punishments: [],
  history: [],
  stats: {
    totalCoins: 0,
  },
  currentSeason: null,
  dailyReviewTime: '21:00',
  seasonCount: 0
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [data, setData] = useState<AppData>(() => {
    const saved = localStorage.getItem('gami_routine_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      const today = new Date().toISOString().split('T')[0];

      parsed.tasks = (parsed.tasks || []).map((t: Task) => {
        if (t.type === 'recurring' && t.completed && t.lastCompletedDate !== today) {
          return { ...t, completed: false };
        }
        return t;
      });
      return parsed;
    }
    return INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem('gami_routine_data', JSON.stringify(data));
  }, [data]);

  const addHistoryEntry = (type: HistoryEntry['type'], title: string, value: number, relatedId?: string) => {
    return {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title,
      value,
      date: new Date().toISOString(),
      relatedId
    } as HistoryEntry;
  };

  const handleCompleteTask = (taskId: string) => {
    const task = data.tasks.find(t => t.id === taskId);
    if (!task || task.completed) return;

    const today = new Date().toISOString().split('T')[0];
    const newCompletionCount = (task.completionCount || 0) + 1;

    const newTasks = data.tasks.map(t => 
      t.id === taskId ? { ...t, completed: true, lastCompletedDate: today, completionCount: newCompletionCount } : t
    );

    setData(prev => ({
      ...prev,
      tasks: newTasks,
      history: [addHistoryEntry('task', task.title, task.xp, task.id), ...prev.history],
      currentSeason: prev.currentSeason ? {
        ...prev.currentSeason,
        currentPoints: prev.currentSeason.currentPoints + task.xp
      } : null,
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins + task.coins }
    }));
  };

  const handleReactivateTask = (taskId: string) => {
    setData(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: false, lastCompletedDate: undefined } : t)
    }));
  };

  const handleDeleteHistoryEntry = (entryId: string) => {
    setData(prev => ({
      ...prev,
      history: prev.history.filter(h => h.id !== entryId)
    }));
  };

  const handleApplyPunishment = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    const pun = data.punishments.find(p => p.id === id);

    if (!pun) return;

    if (pun.lastAppliedDate === today) {
      alert(`⚠️ Esta falha ("${pun.title}") já foi registrada hoje!`);
      return;
    }

    setData(prev => ({
      ...prev,
      punishments: prev.punishments.map(p => p.id === id ? { ...p, lastAppliedDate: today } : p),
      history: [addHistoryEntry('punishment', pun.title, pun.cost, pun.id), ...prev.history],
      stats: { ...prev.stats, totalCoins: prev.stats.totalCoins - pun.cost }
    }));
  };

  const handleCreateSeason = (season: Season) => {
    const nextSeasonNumber = data.seasonCount + 1;
    setData({ 
      ...data, 
      currentSeason: { ...season, seasonNumber: nextSeasonNumber },
      seasonCount: nextSeasonNumber 
    });
  };

  const handleEndSeason = () => {
    if (!data.currentSeason) return;
    const isSuccess = data.currentSeason.currentPoints >= data.currentSeason.targetPoints;
    const historyTitle = `Fim da Season #${data.currentSeason.seasonNumber}: ${isSuccess ? 'Sucesso' : 'Incompleta'}`;

    setData({ 
      ...data, 
      currentSeason: null,
      history: [addHistoryEntry('season_end', historyTitle, data.currentSeason.currentPoints), ...data.history]
    });
    alert(isSuccess ? "🏆 PARABÉNS! Season concluída com sucesso!" : "❌ Season encerrada sem atingir a meta.");
  };

  const handleReset = () => {
    if (confirm('Deseja resetar tudo?')) {
      localStorage.removeItem('gami_routine_data');
      setData(INITIAL_DATA);
    }
  };

  const isNegative = data.stats.totalCoins < 0;

  return (
    <div className="flex flex-col h-screen bg-blue-50 text-slate-800">
      <header className="pt-8 pb-4 px-6 bg-white border-b border-blue-100 shadow-sm flex justify-between items-center relative z-50">
        <div className="flex items-center gap-3">
          <img src={APP_ICON} className="w-12 h-12 rounded-full border-2 border-blue-100 shadow-md object-cover" alt="Logo" />
          <div>
            <h1 className="text-xl font-bold text-blue-600 leading-tight">Patrick's Life</h1>
            <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest">Painel de Evolução</p>
          </div>
        </div>
        <div className="flex flex-col items-end gap-1">
            <div className={`flex items-center px-3 py-1 rounded-full border transition-all ${isNegative ? 'bg-red-50 border-red-300' : 'bg-green-50 border-green-200'}`}>
                <span className="text-sm font-bold mr-1">🪙</span>
                <span className={`text-sm font-black ${isNegative ? 'text-red-600' : 'text-green-600'}`}>
                    {data.stats.totalCoins}
                </span>
            </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            stats={data.stats} tasks={data.tasks} rewards={data.rewards} punishments={data.punishments} season={data.currentSeason}
            onCompleteTask={handleCompleteTask} 
            onPurchaseReward={(id) => {
              const r = data.rewards.find(x => x.id === id);
              if (r && data.stats.totalCoins >= r.cost) {
                setData(prev => ({...prev, stats: {...prev.stats, totalCoins: prev.stats.totalCoins - r.cost}, history: [addHistoryEntry('reward', r.title, r.cost), ...prev.history]}));
              }
            }}
            onApplyPunishment={handleApplyPunishment}
            onCreateSeason={handleCreateSeason}
            onEndSeason={handleEndSeason}
          />
        )}
        {currentView === 'tasks' && <TaskManager tasks={data.tasks} onUpdateTasks={(tasks) => setData({...data, tasks})} onReactivateTask={handleReactivateTask} />}
        {currentView === 'shop' && <RewardShop rewards={data.rewards} coins={data.stats.totalCoins} onUpdateRewards={(rewards) => setData({...data, rewards})} onPurchase={(id) => {
          const r = data.rewards.find(x => x.id === id);
          if (r && data.stats.totalCoins >= r.cost) {
            setData(prev => ({...prev, stats: {...prev.stats, totalCoins: prev.stats.totalCoins - r.cost}, history: [addHistoryEntry('reward', r.title, r.cost), ...prev.history]}));
          }
        }} />}
        {currentView === 'punishments' && <PunishmentManager punishments={data.punishments} onUpdatePunishments={(punishments) => setData({...data, punishments})} onApply={handleApplyPunishment} />}
        {currentView === 'history' && <HistoryManager history={data.history} onDeleteEntry={handleDeleteHistoryEntry} />}
        {currentView === 'settings' && <Settings data={data} onImport={setData} onUpdateTime={(time) => setData({...data, dailyReviewTime: time})} onReset={handleReset} />}
      </main>
      <Navbar activeView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task } from '../types';

interface TaskManagerProps {
  tasks: Task[];
  onUpdateTasks: (tasks: Task[]) => void;
  onReactivateTask: (id: string) => void;
}

const TaskManager: React.FC<TaskManagerProps> = ({ tasks, onUpdateTasks, onReactivateTask }) => {
  const [showForm, setShowForm] = useState(false);
  const [showCompleted, setShowCompleted] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [newTitle, setNewTitle] = useState('');
  const [newXp, setNewXp] = useState(50);
  const [newCoins, setNewCoins] = useState(10);
  const [taskType, setTaskType] = useState<'recurring' | 'one-time'>('recurring');
  const [recurringType, setRecurringType] = useState<'weekly' | 'monthly'>('weekly');
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]);
  const [monthlyWeek, setMonthlyWeek] = useState(1);
  const [monthlyDay, setMonthlyDay] = useState(1);

  const daysOfWeek = [
    { id: 0, label: 'D' }, { id: 1, label: 'S' }, { id: 2, label: 'T' }, 
    { id: 3, label: 'Q' }, { id: 4, label: 'Q' }, { id: 5, label: 'S' }, { id: 6, label: 'S' }
  ];

  const weeksOfMonth = [
    { id: 1, label: '1ª' }, { id: 2, label: '2ª' }, { id: 3, label: '3ª' }, { id: 4, label: '4ª' }, { id: 5, label: 'Última' }
  ];

  const resetForm = () => {
    setNewTitle('');
    setNewXp(50);
    setNewCoins(10);
    setTaskType('recurring');
    setRecurringType('weekly');
    setSelectedDays([1, 2, 3, 4, 5]);
    setMonthlyWeek(1);
    setMonthlyDay(1);
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (task: Task) => {
    setEditingId(task.id);
    setNewTitle(task.title);
    setNewXp(task.xp);
    setNewCoins(task.coins);
    setTaskType(task.type);
    setRecurringType(task.recurringType || 'weekly');
    setSelectedDays(task.recurringDays);
    if (task.monthlyPattern) {
        setMonthlyWeek(task.monthlyPattern.week);
        setMonthlyDay(task.monthlyPattern.day);
    }
    setShowForm(true);
  };

  const saveTask = () => {
    if (!newTitle.trim()) return;

    const taskData: Task = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      title: newTitle,
      xp: newXp,
      coins: newCoins,
      completed: false,
      type: taskType,
      recurringType: taskType === 'recurring' ? recurringType : undefined,
      recurringDays: taskType === 'recurring' && recurringType === 'weekly' ? selectedDays : [],
      monthlyPattern: taskType === 'recurring' && recurringType === 'monthly' ? { week: monthlyWeek, day: monthlyDay } : undefined,
      completionCount: 0
    };

    if (editingId) {
        onUpdateTasks(tasks.map(t => t.id === editingId ? { ...taskData, completed: t.completed, lastCompletedDate: t.lastCompletedDate, completionCount: t.completionCount } : t));
    } else {
        onUpdateTasks([taskData, ...tasks]);
    }
    resetForm();
  };

  const activeTasks = tasks.filter(t => !t.completed || t.type === 'recurring');
  const completedOneTime = tasks.filter(t => t.type === 'one-time' && t.completed);

  return (
    <div className="p-6 pb-32">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Gerenciar Missões</h2>
        <button onClick={() => setShowForm(true)} className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center text-2xl shadow-lg active:scale-95 transition-transform">+</button>
      </div>

      {showForm && (
        <div className="mb-6 bg-white p-6 rounded-3xl border border-blue-100 shadow-2xl space-y-5 animate-in slide-in-from-top duration-300">
          <h3 className="font-bold text-black uppercase text-xs tracking-widest">{editingId ? 'Editar Missão' : 'Nova Missão'}</h3>

          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome da Missão</label>
              <input 
                type="text" 
                className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl focus:outline-none focus:border-blue-400 font-medium"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
              />
            </div>

            <div className="flex gap-2">
                <button onClick={() => setTaskType('recurring')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl border-2 transition-all ${taskType === 'recurring' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>Rotina</button>
                <button onClick={() => setTaskType('one-time')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl border-2 transition-all ${taskType === 'one-time' ? 'bg-purple-600 border-purple-600 text-white' : 'bg-white border-slate-100 text-slate-400'}`}>Pontual</button>
            </div>

            {taskType === 'recurring' && (
              <div className="space-y-4 pt-2 border-t border-slate-50">
                <div className="flex bg-slate-50 p-1 rounded-xl">
                    <button onClick={() => setRecurringType('weekly')} className={`flex-1 py-1.5 text-[9px] font-black uppercase rounded-lg transition-colors ${recurringType === 'weekly' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Semanal</button>
                    <button onClick={() => setRecurringType('monthly')} className={`flex-1 py-1.5 text-[9px] font-black uppercase rounded-lg transition-colors ${recurringType === 'monthly' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Mensal</button>
                </div>

                {recurringType === 'weekly' ? (
                  <div className="flex justify-between px-2">
                    {daysOfWeek.map(day => (
                      <button
                        key={day.id}
                        onClick={() => setSelectedDays(prev => prev.includes(day.id) ? prev.filter(d => d !== day.id) : [...prev, day.id])}
                        className={`w-8 h-8 rounded-full text-[10px] font-bold transition-all ${selectedDays.includes(day.id) ? 'bg-blue-600 text-white border-blue-600' : 'bg-white border-2 border-slate-100 text-slate-400'}`}
                      >
                        {day.label}
                      </button>
                    ))}
                  </div>
                ) : (
                  <div className="space-y-3">
                    <div className="flex justify-between gap-1">
                      {weeksOfMonth.map(w => (
                        <button key={w.id} onClick={() => setMonthlyWeek(w.id)} className={`flex-1 py-2 rounded-xl text-[9px] font-bold border-2 transition-colors ${monthlyWeek === w.id ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-400'}`}>{w.label}</button>
                      ))}
                    </div>
                    <div className="flex justify-between gap-1">
                      {daysOfWeek.map(d => (
                        <button key={d.id} onClick={() => setMonthlyDay(d.id)} className={`w-8 h-8 rounded-xl text-[10px] font-bold border-2 transition-colors ${monthlyDay === d.id ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-50 text-slate-400'}`}>{d.label}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Pts Season</label>
                <input type="number" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold" value={newXp} onChange={e => setNewXp(parseInt(e.target.value) || 0)} />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Moedas 🪙</label>
                <input type="number" className="w-full bg-white text-black border-2 border-slate-100 p-3 rounded-2xl font-bold text-green-600" value={newCoins} onChange={e => setNewCoins(parseInt(e.target.value) || 0)} />
              </div>
            </div>

            <div className="flex gap-2 pt-4">
              <button onClick={resetForm} className="flex-1 py-4 text-slate-400 font-black text-[10px] uppercase">Cancelar</button>
              <button onClick={saveTask} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg active:scale-95">Salvar</button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {activeTasks.map(task => (
          <div key={task.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
            <div className="flex-1 min-w-0 pr-4">
              <span className="block font-bold text-slate-700 truncate">{task.title}</span>
              <div className="flex items-center gap-2 mt-1">
                <span className={`text-[8px] px-1.5 py-0.5 rounded font-black uppercase ${task.type === 'one-time' ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'}`}>
                    {task.recurringType === 'monthly' ? 'Mensal' : task.type === 'one-time' ? 'Pontual' : 'Rotina'}
                </span>
                <span className="text-[9px] text-slate-400 font-bold">{task.xp} pts | {task.coins} 🪙</span>
              </div>
            </div>
            <div className="flex gap-1">
                <button onClick={() => handleEdit(task)} className="p-2 text-blue-400 hover:bg-blue-50 rounded-lg transition-colors">✏️</button>
                <button onClick={() => onUpdateTasks(tasks.filter(t => t.id !== task.id))} className="p-2 text-red-200 hover:text-red-500 rounded-lg transition-colors">🗑️</button>
            </div>
          </div>
        ))}
      </div>

      {completedOneTime.length > 0 && (
        <div className="mt-8">
            <button 
                onClick={() => setShowCompleted(!showCompleted)}
                className="w-full py-2 flex items-center justify-between text-slate-400"
            >
                <span className="text-[10px] font-black uppercase tracking-widest">Missões Pontuais Concluídas ({completedOneTime.length})</span>
                <span className={`transform transition-transform ${showCompleted ? 'rotate-180' : ''}`}>▼</span>
            </button>
            {showCompleted && (
                <div className="mt-3 space-y-2">
                    {completedOneTime.map(task => (
                        <div key={task.id} className="bg-slate-50 p-4 rounded-2xl border border-slate-200 flex items-center justify-between opacity-60">
                            <div className="flex-1 truncate pr-4">
                                <span className="block font-bold text-slate-500 line-through truncate">{task.title}</span>
                                <span className="text-[8px] text-slate-400">Concluída em {task.lastCompletedDate?.split('-').reverse().join('/')}</span>
                            </div>
                            <button 
                                onClick={() => onReactivateTask(task.id)}
                                className="bg-blue-100 text-blue-600 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase active:scale-95"
                            >
                                Reativar
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

export default TaskManager;

import React, { useState } from 'react';
import { Reward } from '../types';

interface RewardShopProps {
  rewards: Reward[];
  coins: number;
  onUpdateRewards: (rewards: Reward[]) => void;
  onPurchase: (id: string) => void;
}

const RewardShop: React.FC<RewardShopProps> = ({ rewards, coins, onUpdateRewards, onPurchase }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newCost, setNewCost] = useState(100);

  const resetForm = () => {
    setNewTitle('');
    setNewCost(100);
    setEditingId(null);
    setShowForm(false);
  };

  const handleEdit = (reward: Reward) => {
    setEditingId(reward.id);
    setNewTitle(reward.title);
    setNewCost(reward.cost);
    setShowForm(true);
  };

  const saveReward = () => {
    if (!newTitle.trim()) return;

    const rewardData: Reward = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      title: newTitle,
      cost: newCost,
      purchased: false,
      description: ''
    };

    if (editingId) {
      onUpdateRewards(rewards.map(r => r.id === editingId ? rewardData : r));
    } else {
      onUpdateRewards([...rewards, rewardData]);
    }
    resetForm();
  };

  const removeReward = (id: string) => {
    if (confirm('Deseja remover este prêmio?')) {
      onUpdateRewards(rewards.filter(r => r.id !== id));
    }
  };

  return (
    <div className="p-6 pb-32">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Loja de Prêmios</h2>
          <p className="text-xs font-bold text-green-600 uppercase tracking-widest">Saldo: {coins} 🪙</p>
        </div>
        <button 
